import pg from "pg";
const { Pool } = pg;

interface MltQuestion {
  stem: string;
  options: string[];
  correctAnswer: number;
  rationaleLong: string;
  blueprintCategory: string;
  subtopic: string;
  difficulty: number;
  cognitiveLevel: string;
  learningObjective: string;
}

const chemistryQuestions: MltQuestion[] = [
  { stem: "A fasting glucose result of 130 mg/dL is obtained on a patient. According to ADA criteria, which of the following is the most appropriate interpretation?", options: ["Normal fasting glucose", "Impaired fasting glucose", "Diagnostic of diabetes mellitus", "Requires an oral glucose tolerance test for confirmation"], correctAnswer: 1, rationaleLong: "According to ADA criteria, impaired fasting glucose (IFG) is defined as a fasting plasma glucose of 100-125 mg/dL. A value of 126 mg/dL or higher on two separate occasions is diagnostic of diabetes. A single value of 130 mg/dL falls into the range suggestive of diabetes but requires confirmation with a repeat test. However, a single elevated fasting glucose of 100-125 is classified as IFG.", blueprintCategory: "Clinical Chemistry", subtopic: "Carbohydrates", difficulty: 2, cognitiveLevel: "application", learningObjective: "Interpret fasting glucose values using ADA criteria" },
  { stem: "Which enzyme is considered the most specific marker for acute pancreatitis?", options: ["Amylase", "Lipase", "Trypsin", "Elastase"], correctAnswer: 1, rationaleLong: "Lipase is the most specific enzyme marker for acute pancreatitis. While amylase rises earlier, it can be elevated in many non-pancreatic conditions (salivary gland disease, macroamylasemia, renal failure). Lipase remains elevated longer and is more specific to pancreatic tissue damage.", blueprintCategory: "Clinical Chemistry", subtopic: "Enzymes", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Identify enzyme markers for pancreatic disease" },
  { stem: "A serum sample appears lipemic. Which of the following analytes is most likely to be falsely elevated due to lipemia?", options: ["Sodium", "Potassium", "Triglycerides", "Chloride"], correctAnswer: 0, rationaleLong: "Lipemia causes a volume displacement effect with indirect ISE methods, leading to falsely decreased sodium and chloride results. However, with direct ISE methods, lipemia does not significantly affect electrolyte measurements. The most common interference is with spectrophotometric assays, where turbidity from lipemia causes falsely elevated results for analytes measured at wavelengths affected by light scattering.", blueprintCategory: "Clinical Chemistry", subtopic: "Lipids & Lipoproteins", difficulty: 3, cognitiveLevel: "application", learningObjective: "Recognize lipemia interference in laboratory testing" },
  { stem: "A patient has the following results: total bilirubin 8.5 mg/dL, direct bilirubin 6.2 mg/dL, AST 450 U/L, ALT 520 U/L, ALP 380 U/L. These findings are most consistent with:", options: ["Hemolytic anemia", "Hepatocellular damage", "Obstructive jaundice", "Gilbert syndrome"], correctAnswer: 1, rationaleLong: "The pattern shows markedly elevated AST and ALT (hepatocellular enzymes), elevated direct bilirubin indicating conjugated hyperbilirubinemia, and moderately elevated ALP. This is most consistent with hepatocellular damage. In obstructive jaundice, ALP would be disproportionately elevated compared to AST/ALT. In hemolytic anemia, indirect bilirubin predominates.", blueprintCategory: "Clinical Chemistry", subtopic: "Liver Function", difficulty: 3, cognitiveLevel: "analysis", learningObjective: "Correlate liver function test patterns with disease states" },
  { stem: "Which of the following is the primary buffer system in blood?", options: ["Phosphate buffer system", "Bicarbonate/carbonic acid buffer system", "Protein buffer system", "Hemoglobin buffer system"], correctAnswer: 1, rationaleLong: "The bicarbonate/carbonic acid buffer system is the primary extracellular buffer system in blood. It maintains blood pH at approximately 7.4 through the equilibrium: CO2 + H2O ⇌ H2CO3 ⇌ H+ + HCO3-. The normal ratio of bicarbonate to carbonic acid is 20:1.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Identify the primary blood buffer system" },
  { stem: "A blood gas result shows pH 7.28, pCO2 55 mmHg, HCO3 26 mEq/L. What is the acid-base status?", options: ["Metabolic acidosis", "Respiratory acidosis", "Metabolic alkalosis", "Respiratory alkalosis"], correctAnswer: 1, rationaleLong: "The low pH (7.28) indicates acidosis. The elevated pCO2 (55 mmHg; normal 35-45) indicates a respiratory cause. The HCO3 is within normal range (22-26), indicating no significant metabolic compensation has occurred yet. This is an uncompensated respiratory acidosis.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 3, cognitiveLevel: "application", learningObjective: "Interpret arterial blood gas results" },
  { stem: "What is the Henderson-Hasselbalch equation used to calculate?", options: ["Anion gap", "Blood pH", "Oxygen saturation", "Base excess"], correctAnswer: 1, rationaleLong: "The Henderson-Hasselbalch equation (pH = pKa + log[A-]/[HA]) is used to calculate blood pH from the ratio of bicarbonate (conjugate base) to carbonic acid (weak acid). In blood gas analysis: pH = 6.1 + log([HCO3-]/(0.03 × pCO2)).", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Understand the Henderson-Hasselbalch equation" },
  { stem: "A patient's serum creatinine is 3.2 mg/dL and BUN is 45 mg/dL. The BUN/creatinine ratio is approximately:", options: ["10:1", "14:1", "20:1", "30:1"], correctAnswer: 1, rationaleLong: "BUN/Creatinine ratio = 45/3.2 = approximately 14:1. The normal ratio is 10:1 to 20:1. This ratio is within normal limits, suggesting intrinsic renal disease (both BUN and creatinine elevated proportionally). A ratio >20:1 would suggest prerenal azotemia.", blueprintCategory: "Clinical Chemistry", subtopic: "Renal Function", difficulty: 2, cognitiveLevel: "application", learningObjective: "Calculate and interpret BUN/creatinine ratio" },
  { stem: "Which of the following proteins is the best indicator of nutritional status?", options: ["Albumin", "Prealbumin (transthyretin)", "Total protein", "Alpha-1 antitrypsin"], correctAnswer: 1, rationaleLong: "Prealbumin (transthyretin) has a short half-life of approximately 2 days, making it the most sensitive indicator of acute changes in nutritional status. Albumin has a half-life of approximately 20 days, making it a poor indicator of acute nutritional changes.", blueprintCategory: "Clinical Chemistry", subtopic: "Proteins & Amino Acids", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Identify protein markers of nutritional status" },
  { stem: "An elevated serum CK-MB with a relative index >5% is most suggestive of:", options: ["Skeletal muscle injury", "Acute myocardial infarction", "Liver disease", "Renal failure"], correctAnswer: 1, rationaleLong: "CK-MB is the cardiac-specific isoenzyme of creatine kinase. A CK-MB relative index (CK-MB/total CK × 100) greater than 5% is indicative of myocardial injury. Skeletal muscle contains primarily CK-MM, and while it contains small amounts of CK-MB, the relative index would typically be <5% in pure skeletal muscle injury.", blueprintCategory: "Clinical Chemistry", subtopic: "Enzymes", difficulty: 3, cognitiveLevel: "application", learningObjective: "Interpret cardiac biomarker results" },
  { stem: "Which specimen type is preferred for glucose testing to minimize glycolysis?", options: ["Serum separator tube", "Sodium fluoride/potassium oxalate tube", "EDTA tube", "Heparinized tube"], correctAnswer: 1, rationaleLong: "Sodium fluoride (NaF) inhibits the glycolytic enzyme enolase, preventing glucose consumption by blood cells. Without a glycolytic inhibitor, glucose decreases approximately 5-7% per hour at room temperature. NaF/potassium oxalate (gray top tube) is the specimen of choice for glucose testing when analysis cannot be performed immediately.", blueprintCategory: "Clinical Chemistry", subtopic: "Carbohydrates", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Select appropriate specimen types for glucose testing" },
  { stem: "A 2-hour postprandial glucose of 210 mg/dL in a non-pregnant adult is classified as:", options: ["Normal", "Impaired glucose tolerance", "Diagnostic of diabetes mellitus", "Pre-diabetes"], correctAnswer: 2, rationaleLong: "According to ADA criteria, a 2-hour plasma glucose ≥200 mg/dL during an oral glucose tolerance test (OGTT) is diagnostic of diabetes mellitus. A value of 140-199 mg/dL indicates impaired glucose tolerance (pre-diabetes). A value <140 mg/dL is considered normal.", blueprintCategory: "Clinical Chemistry", subtopic: "Carbohydrates", difficulty: 2, cognitiveLevel: "application", learningObjective: "Classify glucose tolerance test results" },
  { stem: "Which lipoprotein fraction carries the most cholesterol in the blood?", options: ["Chylomicrons", "VLDL", "LDL", "HDL"], correctAnswer: 2, rationaleLong: "LDL (low-density lipoprotein) carries approximately 60-70% of total serum cholesterol. LDL is considered 'bad cholesterol' because elevated levels are associated with increased risk of atherosclerosis and coronary artery disease. HDL carries about 20-30%, while VLDL carries 10-15%.", blueprintCategory: "Clinical Chemistry", subtopic: "Lipids & Lipoproteins", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Identify cholesterol-carrying lipoproteins" },
  { stem: "The Friedewald equation is used to calculate:", options: ["HDL cholesterol", "LDL cholesterol", "Total cholesterol", "VLDL cholesterol"], correctAnswer: 1, rationaleLong: "The Friedewald equation calculates LDL cholesterol: LDL = Total Cholesterol - HDL - (Triglycerides/5). This equation is valid only when triglycerides are <400 mg/dL. When triglycerides exceed this level, direct LDL measurement must be performed.", blueprintCategory: "Clinical Chemistry", subtopic: "Lipids & Lipoproteins", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Apply the Friedewald equation for LDL calculation" },
  { stem: "A patient has total cholesterol 280 mg/dL, HDL 35 mg/dL, and triglycerides 200 mg/dL. Using the Friedewald equation, what is the calculated LDL?", options: ["185 mg/dL", "205 mg/dL", "225 mg/dL", "245 mg/dL"], correctAnswer: 1, rationaleLong: "Using the Friedewald equation: LDL = Total cholesterol - HDL - (Triglycerides/5) = 280 - 35 - (200/5) = 280 - 35 - 40 = 205 mg/dL. This LDL level is significantly elevated (desirable is <100 mg/dL for high-risk patients).", blueprintCategory: "Clinical Chemistry", subtopic: "Lipids & Lipoproteins", difficulty: 3, cognitiveLevel: "application", learningObjective: "Calculate LDL using the Friedewald equation" },
  { stem: "Which enzyme is most specific for biliary obstruction?", options: ["AST", "ALT", "GGT", "5'-Nucleotidase"], correctAnswer: 3, rationaleLong: "5'-Nucleotidase (5'-NT) is most specific for hepatobiliary disease and helps confirm biliary obstruction when ALP is elevated. Unlike ALP, which can be elevated in bone disease, 5'-NT is not present in bone tissue. GGT is sensitive but not specific, as it is also elevated by alcohol and medications.", blueprintCategory: "Clinical Chemistry", subtopic: "Liver Function", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Differentiate hepatobiliary enzyme markers" },
  { stem: "An elevated indirect (unconjugated) bilirubin with normal direct bilirubin is most consistent with:", options: ["Biliary obstruction", "Hepatitis", "Hemolytic anemia", "Dubin-Johnson syndrome"], correctAnswer: 2, rationaleLong: "Hemolytic anemia causes increased destruction of red blood cells, releasing hemoglobin that is catabolized to unconjugated (indirect) bilirubin. The liver can conjugate only a limited amount, leading to elevated indirect bilirubin. In obstructive and hepatocellular disease, direct (conjugated) bilirubin would also be elevated.", blueprintCategory: "Clinical Chemistry", subtopic: "Liver Function", difficulty: 2, cognitiveLevel: "application", learningObjective: "Correlate bilirubin fractions with disease states" },
  { stem: "Which of the following is the most sensitive marker for early detection of renal dysfunction?", options: ["Serum creatinine", "BUN", "Cystatin C", "Uric acid"], correctAnswer: 2, rationaleLong: "Cystatin C is a low-molecular-weight protein produced at a constant rate by all nucleated cells. It is freely filtered by the glomerulus and not affected by muscle mass, diet, or sex. Cystatin C detects changes in GFR earlier than creatinine, as serum creatinine does not rise until approximately 50% of renal function is lost.", blueprintCategory: "Clinical Chemistry", subtopic: "Renal Function", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Identify early markers of renal dysfunction" },
  { stem: "A patient with chronic kidney disease has a GFR of 22 mL/min/1.73m². What stage of CKD does this represent?", options: ["Stage 2", "Stage 3a", "Stage 4", "Stage 5"], correctAnswer: 2, rationaleLong: "CKD Stage 4 is defined as GFR 15-29 mL/min/1.73m². Stage 3a is 45-59, Stage 3b is 30-44, and Stage 5 is <15 mL/min. A GFR of 22 mL/min falls within Stage 4, indicating severely decreased kidney function.", blueprintCategory: "Clinical Chemistry", subtopic: "Renal Function", difficulty: 3, cognitiveLevel: "application", learningObjective: "Classify CKD stages by GFR" },
  { stem: "Troponin I begins to rise in the serum approximately how many hours after the onset of acute myocardial infarction?", options: ["1-2 hours", "3-6 hours", "12-24 hours", "24-48 hours"], correctAnswer: 1, rationaleLong: "Cardiac troponin I (cTnI) typically begins to rise 3-6 hours after the onset of myocardial injury, peaks at 12-24 hours, and remains elevated for 7-10 days. High-sensitivity troponin assays can detect elevations even earlier. Troponin is the preferred biomarker for diagnosis of acute MI.", blueprintCategory: "Clinical Chemistry", subtopic: "Enzymes", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know the timeline of cardiac biomarker elevation" },
  { stem: "Which electrolyte abnormality can cause peaked T waves on an ECG?", options: ["Hypokalemia", "Hyperkalemia", "Hypocalcemia", "Hypernatremia"], correctAnswer: 1, rationaleLong: "Hyperkalemia (elevated serum potassium) can cause peaked (tall, narrow) T waves on ECG. As potassium levels continue to rise, other ECG changes appear: widened QRS complex, flattened P waves, and eventually sine wave pattern. Critical hyperkalemia (>6.5 mEq/L) can lead to cardiac arrest.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Correlate electrolyte abnormalities with clinical findings" },
  { stem: "A specimen collected in a green-top tube shows K+ of 8.2 mEq/L. The next step should be:", options: ["Report the result immediately as critical", "Repeat on a new specimen collected with proper technique", "Perform a blood gas to verify", "Add more heparin to the specimen"], correctAnswer: 1, rationaleLong: "A potassium of 8.2 mEq/L is critically high and could be life-threatening, but it may also be due to hemolysis, difficult venipuncture, or improper specimen handling. Before reporting a critical result, a new specimen should be collected to verify the result. Visual inspection for hemolysis should also be performed.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 3, cognitiveLevel: "application", learningObjective: "Apply quality assurance to critical electrolyte results" },
  { stem: "Which of the following thyroid function test results is most consistent with primary hypothyroidism?", options: ["Elevated TSH, elevated free T4", "Decreased TSH, decreased free T4", "Elevated TSH, decreased free T4", "Decreased TSH, elevated free T4"], correctAnswer: 2, rationaleLong: "Primary hypothyroidism is caused by thyroid gland failure. The decreased thyroid hormone production leads to decreased free T4, which triggers the anterior pituitary to increase TSH production via negative feedback. Thus, elevated TSH with decreased free T4 is the classic pattern.", blueprintCategory: "Clinical Chemistry", subtopic: "Endocrine / Hormones", difficulty: 2, cognitiveLevel: "application", learningObjective: "Interpret thyroid function test patterns" },
  { stem: "Which tumor marker is most commonly used to monitor treatment of prostate cancer?", options: ["CEA", "AFP", "PSA", "CA-125"], correctAnswer: 2, rationaleLong: "Prostate-specific antigen (PSA) is the primary tumor marker for monitoring prostate cancer treatment response and detecting recurrence. PSA levels should decline after successful treatment. CEA is used for colorectal cancer, AFP for hepatocellular carcinoma and germ cell tumors, and CA-125 for ovarian cancer.", blueprintCategory: "Clinical Chemistry", subtopic: "Tumor Markers", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Match tumor markers with cancer types" },
  { stem: "What is the therapeutic range for lithium?", options: ["0.1-0.5 mEq/L", "0.6-1.2 mEq/L", "2.0-4.0 mEq/L", "5.0-10.0 mEq/L"], correctAnswer: 1, rationaleLong: "The therapeutic range for lithium is 0.6-1.2 mEq/L (some references use 0.6-1.5). Levels above 1.5 mEq/L are associated with toxicity, and levels above 2.0 mEq/L can be life-threatening. Blood specimens for lithium monitoring should be collected 12 hours after the last dose (trough level).", blueprintCategory: "Clinical Chemistry", subtopic: "Therapeutic Drug Monitoring", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know therapeutic drug ranges" },
  { stem: "A patient taking warfarin has an INR of 5.2. Which analyte is being indirectly monitored?", options: ["Activated partial thromboplastin time", "Prothrombin time", "Thrombin time", "Fibrinogen level"], correctAnswer: 1, rationaleLong: "INR (International Normalized Ratio) is calculated from the prothrombin time (PT) and is used to monitor warfarin therapy. Warfarin inhibits vitamin K-dependent clotting factors (II, VII, IX, X). The PT/INR is the standard test for monitoring warfarin, with a typical therapeutic INR of 2.0-3.0.", blueprintCategory: "Clinical Chemistry", subtopic: "Therapeutic Drug Monitoring", difficulty: 2, cognitiveLevel: "application", learningObjective: "Understand INR and warfarin monitoring" },
  { stem: "Which method principle is used in ion-selective electrode (ISE) measurement of sodium?", options: ["Spectrophotometry", "Potentiometry", "Amperometry", "Coulometry"], correctAnswer: 1, rationaleLong: "Ion-selective electrodes measure electrolytes using potentiometry, which measures the electrical potential (voltage) difference between a reference electrode and a measuring electrode. The potential is proportional to the log of the ion activity (Nernst equation). ISE is the most common method for measuring Na+, K+, Cl-, and ionized Ca2+.", blueprintCategory: "Clinical Chemistry", subtopic: "Instrumentation (Spectrophotometry, ISE, HPLC)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Identify analytical methods for electrolyte measurement" },
  { stem: "Beer's Law states that absorbance is directly proportional to:", options: ["Wavelength of light", "Concentration and path length", "Temperature of the solution", "Volume of the cuvette"], correctAnswer: 1, rationaleLong: "Beer's Law (A = εbc) states that absorbance is directly proportional to both the concentration of the absorbing substance (c) and the path length of light through the solution (b). ε is the molar absorptivity coefficient. This relationship is linear only within certain concentration ranges.", blueprintCategory: "Clinical Chemistry", subtopic: "Instrumentation (Spectrophotometry, ISE, HPLC)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Understand Beer's Law" },
  { stem: "A spectrophotometer is reading an absorbance of 0.301. What is the percent transmittance?", options: ["30.1%", "50%", "69.9%", "75%"], correctAnswer: 1, rationaleLong: "Absorbance and percent transmittance are related by the equation: A = -log(%T/100) or A = 2 - log(%T). An absorbance of 0.301 corresponds to 50% transmittance because -log(0.50) = 0.301. This relationship is important for understanding spectrophotometric measurements.", blueprintCategory: "Clinical Chemistry", subtopic: "Instrumentation (Spectrophotometry, ISE, HPLC)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Convert between absorbance and transmittance" },
  { stem: "HPLC is the preferred method for measuring which of the following?", options: ["Serum sodium", "Hemoglobin A1c", "Total protein", "Serum glucose"], correctAnswer: 1, rationaleLong: "High-performance liquid chromatography (HPLC) is considered the reference method for measuring hemoglobin A1c (glycated hemoglobin). HPLC separates hemoglobin variants based on charge differences and provides accurate quantification of HbA1c, HbA2, HbF, and abnormal hemoglobins.", blueprintCategory: "Clinical Chemistry", subtopic: "Instrumentation (Spectrophotometry, ISE, HPLC)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Identify appropriate analytical methods" },
  { stem: "A chemistry analyzer repeatedly gives results that are 15% higher than expected for glucose on quality control. The most likely problem is:", options: ["Random error", "Systematic error (bias)", "Imprecision", "Matrix effect"], correctAnswer: 1, rationaleLong: "Consistent deviation in one direction (always high or always low) represents systematic error or bias. This could be due to calibration issues, reagent deterioration, or method problems. Random error would show results distributed both above and below the expected value. Systematic error requires investigation of the analytical system.", blueprintCategory: "Clinical Chemistry", subtopic: "Instrumentation (Spectrophotometry, ISE, HPLC)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Distinguish between random and systematic error" },
  { stem: "Hemolysis in a serum specimen would cause a falsely elevated result for which of the following?", options: ["Sodium", "Glucose", "Potassium", "Chloride"], correctAnswer: 2, rationaleLong: "Hemolysis releases intracellular contents into the serum. Since RBCs contain a much higher concentration of potassium than plasma (approximately 150 mEq/L intracellular vs. 3.5-5.0 mEq/L extracellular), even slight hemolysis can significantly elevate serum potassium results. Other analytes affected include LDH, AST, and iron.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 2, cognitiveLevel: "application", learningObjective: "Recognize the effects of hemolysis on laboratory results" },
  { stem: "Which of the following is an acute-phase reactant that increases during inflammation?", options: ["Albumin", "Transferrin", "C-reactive protein", "Prealbumin"], correctAnswer: 2, rationaleLong: "C-reactive protein (CRP) is a positive acute-phase reactant that increases rapidly during inflammation, infection, and tissue injury. Albumin, transferrin, and prealbumin are negative acute-phase reactants that decrease during the acute-phase response.", blueprintCategory: "Clinical Chemistry", subtopic: "Proteins & Amino Acids", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Identify acute-phase reactants" },
  { stem: "Serum protein electrophoresis showing a monoclonal spike (M-spike) in the gamma region is most suggestive of:", options: ["Chronic liver disease", "Nephrotic syndrome", "Multiple myeloma", "Acute inflammation"], correctAnswer: 2, rationaleLong: "A monoclonal spike (M-spike or M-component) in the gamma region of serum protein electrophoresis is characteristic of multiple myeloma or other plasma cell dyscrasias (such as Waldenström macroglobulinemia). This represents a monoclonal immunoglobulin produced by neoplastic plasma cells. Chronic liver disease shows polyclonal gammopathy (broad-based increase).", blueprintCategory: "Clinical Chemistry", subtopic: "Proteins & Amino Acids", difficulty: 3, cognitiveLevel: "application", learningObjective: "Interpret serum protein electrophoresis patterns" },
  { stem: "Which of the following HbA1c values indicates good glycemic control in a diabetic patient?", options: ["< 5.0%", "< 7.0%", "< 9.0%", "< 11.0%"], correctAnswer: 1, rationaleLong: "The ADA recommends an HbA1c target of < 7.0% for most adults with diabetes, which corresponds to an estimated average glucose of approximately 154 mg/dL. HbA1c reflects average blood glucose over the preceding 2-3 months (the lifespan of red blood cells). Values > 9% indicate poor glycemic control.", blueprintCategory: "Clinical Chemistry", subtopic: "Carbohydrates", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know HbA1c treatment targets" },
  { stem: "What is the anion gap used to evaluate?", options: ["Respiratory function", "Metabolic acidosis classification", "Liver function", "Coagulation status"], correctAnswer: 1, rationaleLong: "The anion gap (AG = Na+ - (Cl- + HCO3-)) is used to classify metabolic acidosis as either high anion gap (e.g., diabetic ketoacidosis, lactic acidosis, renal failure, toxic ingestions) or normal anion gap (hyperchloremic acidosis, e.g., diarrhea, RTA). Normal AG is approximately 8-12 mEq/L.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Understand the clinical utility of anion gap" },
  { stem: "A patient has Na+ 140, K+ 4.0, Cl- 100, HCO3- 12. What is the anion gap?", options: ["16 mEq/L", "28 mEq/L", "32 mEq/L", "40 mEq/L"], correctAnswer: 1, rationaleLong: "Anion gap = Na+ - (Cl- + HCO3-) = 140 - (100 + 12) = 28 mEq/L. This is a high anion gap (normal 8-12 mEq/L), which combined with the low bicarbonate indicates a high anion gap metabolic acidosis. Common causes include diabetic ketoacidosis, lactic acidosis, uremia, and toxic ingestions (MUDPILES mnemonic).", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 3, cognitiveLevel: "application", learningObjective: "Calculate and interpret the anion gap" },
  { stem: "Which of the following conditions would cause an elevated serum osmolality?", options: ["SIADH", "Diabetes insipidus", "Water intoxication", "Hypothyroidism"], correctAnswer: 1, rationaleLong: "Diabetes insipidus (DI) results in the inability to concentrate urine due to lack of ADH (central DI) or renal unresponsiveness to ADH (nephrogenic DI). This leads to excessive water loss, dehydration, and elevated serum osmolality. SIADH causes the opposite — water retention and decreased serum osmolality.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 3, cognitiveLevel: "application", learningObjective: "Correlate osmolality with clinical conditions" },
  { stem: "What does an osmolal gap >10 mOsm/kg indicate?", options: ["Normal finding", "Presence of unmeasured osmotically active substances", "Renal tubular acidosis", "Hepatic failure"], correctAnswer: 1, rationaleLong: "An osmolal gap (measured osmolality - calculated osmolality) greater than 10 mOsm/kg indicates the presence of unmeasured osmotically active substances in the blood. Common causes include ethanol, methanol, ethylene glycol, isopropanol, and mannitol. This is an important finding in the evaluation of suspected toxic ingestions.", blueprintCategory: "Clinical Chemistry", subtopic: "Toxicology", difficulty: 4, cognitiveLevel: "application", learningObjective: "Interpret osmolal gap in toxicology" },
  { stem: "A urine drug screen is positive for benzodiazepines. Which method should be used for confirmation?", options: ["Immunoassay", "HPLC", "GC-MS or LC-MS/MS", "Thin-layer chromatography"], correctAnswer: 2, rationaleLong: "Gas chromatography-mass spectrometry (GC-MS) or liquid chromatography-tandem mass spectrometry (LC-MS/MS) are the gold standard confirmatory methods for drug testing. Initial immunoassay screening tests can have false positives due to cross-reactivity. Mass spectrometry provides definitive identification based on molecular fragmentation patterns.", blueprintCategory: "Clinical Chemistry", subtopic: "Toxicology", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know confirmatory methods for drug testing" },
  { stem: "Elevated AFP (alpha-fetoprotein) in a non-pregnant adult is most associated with:", options: ["Prostate cancer", "Hepatocellular carcinoma", "Breast cancer", "Lung cancer"], correctAnswer: 1, rationaleLong: "Alpha-fetoprotein (AFP) is a tumor marker associated with hepatocellular carcinoma (HCC) and germ cell tumors (testicular/ovarian). It is also elevated in acute and chronic hepatitis, cirrhosis, and pregnancy. AFP is used for screening high-risk populations for HCC and monitoring treatment response.", blueprintCategory: "Clinical Chemistry", subtopic: "Tumor Markers", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Associate tumor markers with malignancies" },
  { stem: "CA-125 is primarily used as a tumor marker for:", options: ["Colon cancer", "Ovarian cancer", "Breast cancer", "Pancreatic cancer"], correctAnswer: 1, rationaleLong: "CA-125 (cancer antigen 125) is the primary tumor marker for epithelial ovarian cancer. It is used to monitor treatment response and detect recurrence. CA-125 can also be elevated in endometriosis, pelvic inflammatory disease, pregnancy, and other malignancies. It is not recommended as a general screening tool.", blueprintCategory: "Clinical Chemistry", subtopic: "Tumor Markers", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know tumor marker associations" },
  { stem: "Which hormone is measured to confirm ovulation?", options: ["Estradiol", "Progesterone", "FSH", "LH"], correctAnswer: 1, rationaleLong: "Progesterone levels rise significantly after ovulation due to the formation of the corpus luteum. A mid-luteal phase progesterone level >3 ng/mL confirms that ovulation has occurred. LH surges before ovulation and triggers it, while estradiol peaks just before the LH surge.", blueprintCategory: "Clinical Chemistry", subtopic: "Endocrine / Hormones", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Understand reproductive hormone testing" },
  { stem: "A patient with suspected Cushing syndrome has an elevated 24-hour urine cortisol. Which confirmatory test would be most appropriate?", options: ["Random serum cortisol", "Low-dose dexamethasone suppression test", "ACTH stimulation test", "Aldosterone-to-renin ratio"], correctAnswer: 1, rationaleLong: "The low-dose dexamethasone suppression test (1 mg overnight DST) is used to confirm Cushing syndrome. In normal individuals, dexamethasone suppresses cortisol production. In Cushing syndrome, cortisol remains elevated despite dexamethasone administration. The ACTH stimulation test is used for adrenal insufficiency.", blueprintCategory: "Clinical Chemistry", subtopic: "Endocrine / Hormones", difficulty: 4, cognitiveLevel: "application", learningObjective: "Select appropriate confirmatory tests for endocrine disorders" },
  { stem: "A serum sample with total calcium of 11.5 mg/dL and albumin of 2.0 g/dL. What is the corrected calcium?", options: ["11.5 mg/dL", "12.3 mg/dL", "13.1 mg/dL", "13.9 mg/dL"], correctAnswer: 2, rationaleLong: "Corrected calcium accounts for low albumin: Corrected Ca = Measured Ca + 0.8 × (4.0 - Albumin) = 11.5 + 0.8 × (4.0 - 2.0) = 11.5 + 1.6 = 13.1 mg/dL. This corrected value reveals true hypercalcemia that might be masked by hypoalbuminemia.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 3, cognitiveLevel: "application", learningObjective: "Calculate corrected calcium" },
  { stem: "Metabolic alkalosis with hypokalemia is commonly caused by:", options: ["Diabetic ketoacidosis", "Renal tubular acidosis", "Persistent vomiting", "Diarrhea"], correctAnswer: 2, rationaleLong: "Persistent vomiting leads to loss of hydrochloric acid (HCl) from the stomach, causing metabolic alkalosis. The kidneys compensate by retaining H+ and excreting K+ and HCO3-, leading to hypokalemia. Diarrhea causes metabolic acidosis due to loss of bicarbonate.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 3, cognitiveLevel: "application", learningObjective: "Correlate acid-base disorders with clinical conditions" },
  { stem: "The Jaffe reaction is used to measure:", options: ["Bilirubin", "Creatinine", "Uric acid", "Ammonia"], correctAnswer: 1, rationaleLong: "The Jaffe reaction (alkaline picrate method) is the classic colorimetric method for measuring serum creatinine. Creatinine reacts with picric acid in alkaline solution to form a red-orange chromogen. The reaction has known interferences including ketones, glucose, proteins, and cephalosporin antibiotics. Enzymatic methods have fewer interferences.", blueprintCategory: "Clinical Chemistry", subtopic: "Renal Function", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know analytical methods for creatinine" },
  { stem: "Which specimen is required for ionized calcium measurement?", options: ["Serum separator tube", "Anaerobic heparinized specimen", "EDTA tube", "Sodium fluoride tube"], correctAnswer: 1, rationaleLong: "Ionized calcium must be measured on an anaerobic heparinized specimen (no gel separator). Exposure to air causes CO2 loss, increasing pH and decreasing ionized calcium. EDTA chelates calcium and cannot be used. Lithium heparin is the preferred anticoagulant.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Select appropriate specimens for ionized calcium" },
  { stem: "Which of the following best describes the clinical significance of elevated LD (lactate dehydrogenase)?", options: ["Highly specific for liver disease", "Nonspecific marker of tissue damage", "Specific for myocardial infarction", "Specific for hemolytic anemia"], correctAnswer: 1, rationaleLong: "LD (LDH) is a nonspecific marker found in almost all body tissues including heart, liver, skeletal muscle, kidney, and erythrocytes. Elevated LD indicates tissue damage but does not localize the source. LD isoenzyme patterns can help identify the tissue of origin (LD1 and LD2 for cardiac, LD5 for liver/skeletal muscle).", blueprintCategory: "Clinical Chemistry", subtopic: "Enzymes", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Understand the clinical significance of LDH" },
  { stem: "An LD flip (LD1 > LD2) is characteristic of:", options: ["Liver disease", "Skeletal muscle injury", "Myocardial infarction", "Pulmonary embolism"], correctAnswer: 2, rationaleLong: "An 'LD flip' occurs when LD1 is greater than LD2 (normal ratio is LD2 > LD1). This pattern is characteristic of myocardial infarction because the heart contains predominantly LD1. The LD flip can also occur in hemolytic anemia and megaloblastic anemia because mature RBCs also contain primarily LD1.", blueprintCategory: "Clinical Chemistry", subtopic: "Enzymes", difficulty: 3, cognitiveLevel: "application", learningObjective: "Interpret LDH isoenzyme patterns" },
  { stem: "Which enzyme is most useful for detecting chronic alcohol abuse?", options: ["AST", "ALT", "GGT", "ALP"], correctAnswer: 2, rationaleLong: "Gamma-glutamyltransferase (GGT) is the most sensitive enzyme marker for chronic alcohol abuse and alcohol-related liver damage. GGT is induced by alcohol and certain drugs (phenytoin, barbiturates). While not specific for alcohol, a significantly elevated GGT with disproportionately lower AST/ALT suggests alcohol as the cause.", blueprintCategory: "Clinical Chemistry", subtopic: "Liver Function", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Identify enzyme markers for alcohol abuse" },
  { stem: "A diabetic patient presents with blood glucose of 650 mg/dL, serum ketones strongly positive, pH 7.10, and HCO3 8 mEq/L. This presentation is consistent with:", options: ["Hypoglycemic episode", "Diabetic ketoacidosis", "Hyperosmolar hyperglycemic state", "Lactic acidosis"], correctAnswer: 1, rationaleLong: "Diabetic ketoacidosis (DKA) is characterized by hyperglycemia (usually >250 mg/dL), positive ketones, metabolic acidosis (low pH, low HCO3), and a high anion gap. HHS (hyperosmolar hyperglycemic state) typically presents with glucose >600 mg/dL but without significant ketosis or acidosis. The presence of ketonemia and acidosis distinguishes DKA.", blueprintCategory: "Clinical Chemistry", subtopic: "Carbohydrates", difficulty: 3, cognitiveLevel: "analysis", learningObjective: "Differentiate DKA from HHS" },
  { stem: "Which hormone is elevated in primary hyperparathyroidism?", options: ["Calcitonin", "PTH (parathyroid hormone)", "Vitamin D", "Cortisol"], correctAnswer: 1, rationaleLong: "In primary hyperparathyroidism, one or more parathyroid glands autonomously produce excess PTH, usually due to a parathyroid adenoma. This leads to elevated PTH and elevated serum calcium (hypercalcemia). Calcitonin, produced by the thyroid C-cells, opposes PTH action and is a tumor marker for medullary thyroid cancer.", blueprintCategory: "Clinical Chemistry", subtopic: "Endocrine / Hormones", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Understand parathyroid disorders" },
  { stem: "Vanillylmandelic acid (VMA) in urine is elevated in:", options: ["Diabetes mellitus", "Pheochromocytoma", "Addison disease", "Cushing syndrome"], correctAnswer: 1, rationaleLong: "VMA is the final metabolite of catecholamines (epinephrine and norepinephrine). Elevated urinary VMA is a screening test for pheochromocytoma (adrenal medullary tumor) and neuroblastoma. Plasma-free metanephrines are now preferred as the initial screening test due to higher sensitivity.", blueprintCategory: "Clinical Chemistry", subtopic: "Endocrine / Hormones", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know catecholamine metabolite testing" },
  { stem: "Phenylketonuria (PKU) is caused by a deficiency of which enzyme?", options: ["Galactose-1-phosphate uridyltransferase", "Phenylalanine hydroxylase", "Hexosaminidase A", "Glucose-6-phosphatase"], correctAnswer: 1, rationaleLong: "PKU is caused by deficiency of phenylalanine hydroxylase, which converts phenylalanine to tyrosine. Accumulation of phenylalanine leads to intellectual disability if untreated. Newborn screening tests detect elevated phenylalanine in blood spots. Treatment involves a phenylalanine-restricted diet.", blueprintCategory: "Clinical Chemistry", subtopic: "Proteins & Amino Acids", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know the enzyme deficiency in PKU" },
  { stem: "Which analyte is used as the primary screening test for iron deficiency?", options: ["Serum iron", "Ferritin", "Total iron-binding capacity", "Transferrin saturation"], correctAnswer: 1, rationaleLong: "Serum ferritin is the best single test for screening for iron deficiency because it reflects total body iron stores. A low ferritin (<12 ng/mL) is diagnostic of iron deficiency. However, ferritin is also an acute-phase reactant, so it may be falsely normal or elevated in the presence of inflammation, infection, or liver disease.", blueprintCategory: "Clinical Chemistry", subtopic: "Proteins & Amino Acids", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know iron studies interpretation" },
  { stem: "In iron deficiency anemia, which of the following patterns is expected?", options: ["Low ferritin, low TIBC, high serum iron", "Low ferritin, high TIBC, low serum iron", "High ferritin, low TIBC, high serum iron", "Normal ferritin, normal TIBC, low serum iron"], correctAnswer: 1, rationaleLong: "Iron deficiency anemia shows: decreased ferritin (depleted iron stores), increased TIBC (the body increases transferrin production to capture more iron), decreased serum iron, and decreased transferrin saturation. This is in contrast to anemia of chronic disease where ferritin is normal/elevated and TIBC is decreased.", blueprintCategory: "Clinical Chemistry", subtopic: "Proteins & Amino Acids", difficulty: 3, cognitiveLevel: "application", learningObjective: "Interpret iron studies in anemia" },
  { stem: "Which of the following conditions would result in elevated serum uric acid?", options: ["Hypothyroidism", "Gout", "Wilson disease", "Phenylketonuria"], correctAnswer: 1, rationaleLong: "Gout is caused by the deposition of monosodium urate crystals in joints due to hyperuricemia (elevated serum uric acid). Uric acid is the end product of purine metabolism. Other causes of hyperuricemia include renal insufficiency, high-purine diet, tumor lysis syndrome, and certain medications (thiazide diuretics).", blueprintCategory: "Clinical Chemistry", subtopic: "Renal Function", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Associate uric acid with clinical conditions" },
  { stem: "Which method is used for direct measurement of HDL cholesterol?", options: ["Ultracentrifugation", "Homogeneous immunoinhibition assay", "Friedewald calculation", "Gel electrophoresis"], correctAnswer: 1, rationaleLong: "Homogeneous (direct) HDL assays use specific antibodies or surfactants to selectively solubilize HDL particles while blocking non-HDL lipoproteins, allowing direct measurement of HDL-C without ultracentrifugation or precipitation steps. These automated assays have largely replaced the traditional precipitation methods.", blueprintCategory: "Clinical Chemistry", subtopic: "Lipids & Lipoproteins", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know HDL measurement methods" },
  { stem: "A patient with a pCO2 of 28 mmHg and pH of 7.50 has:", options: ["Respiratory acidosis", "Metabolic acidosis", "Respiratory alkalosis", "Metabolic alkalosis"], correctAnswer: 2, rationaleLong: "A pH of 7.50 (elevated) indicates alkalosis. A pCO2 of 28 mmHg (decreased, normal 35-45) indicates the cause is respiratory — the patient is hyperventilating and blowing off CO2. This is respiratory alkalosis. Common causes include anxiety, pain, fever, salicylate toxicity, and CNS disorders.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 2, cognitiveLevel: "application", learningObjective: "Classify acid-base disorders" },
  { stem: "Which serum marker has the longest elevation period after an acute myocardial infarction?", options: ["Myoglobin", "CK-MB", "Troponin I", "AST"], correctAnswer: 2, rationaleLong: "Troponin I remains elevated for 7-10 days (some sources say up to 14 days) after acute MI, making it the cardiac biomarker with the longest elevation. Myoglobin rises first (1-3 hours) but returns to normal within 24 hours. CK-MB peaks at 12-24 hours and returns to normal in 2-3 days.", blueprintCategory: "Clinical Chemistry", subtopic: "Enzymes", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know cardiac biomarker kinetics" },
  { stem: "What does a positive Bence Jones protein test indicate?", options: ["Nephrotic syndrome", "Multiple myeloma", "Acute glomerulonephritis", "Urinary tract infection"], correctAnswer: 1, rationaleLong: "Bence Jones proteins are monoclonal immunoglobulin light chains (kappa or lambda) found in the urine of patients with multiple myeloma and other plasma cell dyscrasias. They are small enough to pass through the glomerular membrane. Detection is by urine protein electrophoresis and immunofixation.", blueprintCategory: "Clinical Chemistry", subtopic: "Proteins & Amino Acids", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Recognize Bence Jones proteinuria" },
  { stem: "Which of the following medications requires peak and trough level monitoring?", options: ["Aspirin", "Gentamicin", "Acetaminophen", "Ibuprofen"], correctAnswer: 1, rationaleLong: "Aminoglycoside antibiotics (gentamicin, tobramycin, amikacin) require both peak and trough level monitoring due to their narrow therapeutic index. Peak levels assess efficacy (drawn 30 min after IV infusion), while trough levels assess toxicity risk (drawn just before the next dose). Ototoxicity and nephrotoxicity are the major adverse effects.", blueprintCategory: "Clinical Chemistry", subtopic: "Therapeutic Drug Monitoring", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know drugs requiring therapeutic monitoring" },
  { stem: "A stool specimen tests positive for fecal occult blood. Which substance can cause a false-positive result with the guaiac method?", options: ["Vitamin C", "Red meat", "Antacids", "Iron supplements"], correctAnswer: 1, rationaleLong: "The guaiac-based fecal occult blood test (gFOBT) relies on the peroxidase activity of hemoglobin. Red meat contains hemoglobin and myoglobin, which have peroxidase activity and can cause false-positive results. Patients are instructed to avoid red meat for 3 days before testing. Vitamin C (ascorbic acid) can cause false-negative results.", blueprintCategory: "Clinical Chemistry", subtopic: "Carbohydrates", difficulty: 3, cognitiveLevel: "application", learningObjective: "Understand fecal occult blood test interferences" },
  { stem: "What is the reference method for serum total protein measurement?", options: ["Biuret method", "Kjeldahl method", "Bromocresol green method", "Refractometry"], correctAnswer: 1, rationaleLong: "The Kjeldahl method (nitrogen analysis) is the reference method for total protein measurement. However, the biuret method is the most commonly used routine method. The biuret reaction involves complexation of Cu2+ with peptide bonds in alkaline solution to form a violet color. Bromocresol green and bromocresol purple are used specifically for albumin.", blueprintCategory: "Clinical Chemistry", subtopic: "Proteins & Amino Acids", difficulty: 4, cognitiveLevel: "recall", learningObjective: "Know reference methods for protein analysis" },
  { stem: "Which of the following conditions causes a decreased serum albumin?", options: ["Dehydration", "Nephrotic syndrome", "Hemoconcentration", "Addison disease"], correctAnswer: 1, rationaleLong: "Nephrotic syndrome causes massive proteinuria (>3.5 g/day), predominantly albumin, leading to hypoalbuminemia. The loss of albumin results in decreased oncotic pressure, causing edema. Other causes of low albumin include liver disease (decreased synthesis), malnutrition, and chronic inflammation.", blueprintCategory: "Clinical Chemistry", subtopic: "Proteins & Amino Acids", difficulty: 2, cognitiveLevel: "application", learningObjective: "Correlate albumin levels with clinical conditions" },
  { stem: "An ammonia level should be measured on which specimen?", options: ["Frozen EDTA plasma transported on ice", "Room temperature serum", "Heparinized whole blood at 37°C", "Refrigerated serum separator tube"], correctAnswer: 0, rationaleLong: "Ammonia specimens must be collected in EDTA or heparin, placed on ice immediately, and analyzed within 15-30 minutes. Plasma should be separated promptly and frozen if analysis is delayed. Ammonia is released from red blood cells, amino acids, and proteins at room temperature, causing falsely elevated results.", blueprintCategory: "Clinical Chemistry", subtopic: "Liver Function", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know specimen requirements for ammonia" },
  { stem: "The anion gap is calculated as:", options: ["Na+ + K+ - Cl- - HCO3-", "Na+ - (Cl- + HCO3-)", "Na+ + Cl- - K+ - HCO3-", "(Na+ + K+) / (Cl- + HCO3-)"], correctAnswer: 1, rationaleLong: "The most commonly used anion gap formula is: AG = Na+ - (Cl- + HCO3-). Normal range is 8-12 mEq/L. Some formulas include potassium: AG = (Na+ + K+) - (Cl- + HCO3-), with a normal range of 12-16 mEq/L. The simplified formula (without K+) is preferred in most clinical settings.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know the anion gap formula" },
  { stem: "A point-of-care glucose meter reads 45 mg/dL on a critically ill ICU patient. The most appropriate action is:", options: ["Treat immediately for hypoglycemia", "Repeat using a laboratory glucose method", "Calibrate the glucose meter", "Verify the result with a new test strip"], correctAnswer: 1, rationaleLong: "Point-of-care glucose meters have limitations in critically ill patients, including interference from medications (acetaminophen, dopamine), altered hematocrit, hypotension, and edema. For critical values or ICU patients, confirmation with a laboratory-based glucose method (venous or arterial sample) is recommended before treatment decisions.", blueprintCategory: "Clinical Chemistry", subtopic: "Carbohydrates", difficulty: 3, cognitiveLevel: "application", learningObjective: "Understand POCT glucose limitations" },
  { stem: "Which immunoglobulin is present in the highest concentration in serum?", options: ["IgA", "IgG", "IgM", "IgE"], correctAnswer: 1, rationaleLong: "IgG is the most abundant immunoglobulin in serum, comprising approximately 75-80% of total serum immunoglobulins. It is the only immunoglobulin that crosses the placenta. IgA is the predominant immunoglobulin in secretions. IgM is the first antibody produced in a primary immune response. IgE is present in the lowest concentration.", blueprintCategory: "Clinical Chemistry", subtopic: "Proteins & Amino Acids", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know immunoglobulin properties" },
  { stem: "What is the primary clinical use of BNP (B-type natriuretic peptide) testing?", options: ["Diagnosis of pulmonary embolism", "Diagnosis and monitoring of heart failure", "Screening for coronary artery disease", "Monitoring anticoagulant therapy"], correctAnswer: 1, rationaleLong: "BNP and NT-proBNP are cardiac biomarkers released from ventricular myocytes in response to volume overload and pressure. They are used primarily for diagnosis, severity assessment, and monitoring of congestive heart failure. Elevated BNP helps differentiate cardiac from pulmonary causes of dyspnea.", blueprintCategory: "Clinical Chemistry", subtopic: "Enzymes", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know BNP clinical applications" },
  { stem: "A serum specimen shows icteric interference. Which of the following analytes is most affected?", options: ["Glucose", "Total bilirubin", "Creatinine", "Sodium"], correctAnswer: 2, rationaleLong: "Icteric (jaundiced) specimens contain elevated bilirubin, which absorbs light at approximately 450-460 nm. This causes spectral interference with assays that measure at or near these wavelengths. Creatinine measured by the Jaffe method can be negatively interfered by bilirubin. Direct bilirubin itself is the cause of the icterus.", blueprintCategory: "Clinical Chemistry", subtopic: "Instrumentation (Spectrophotometry, ISE, HPLC)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Identify icteric interference effects" },
  { stem: "The enzyme-multiplied immunoassay technique (EMIT) is based on which principle?", options: ["Competitive binding with labeled enzyme", "Sandwich immunoassay with two antibodies", "Agglutination of antigen-coated particles", "Fluorescence polarization"], correctAnswer: 0, rationaleLong: "EMIT (enzyme-multiplied immunoassay technique) is a homogeneous competitive immunoassay. The drug in the patient's sample competes with enzyme-labeled drug for binding to antibody. When labeled drug binds antibody, the enzyme is inhibited. More patient drug = more free labeled drug = more enzyme activity = higher signal.", blueprintCategory: "Clinical Chemistry", subtopic: "Toxicology", difficulty: 4, cognitiveLevel: "recall", learningObjective: "Understand immunoassay principles" },
  { stem: "Which of the following electrolyte changes is seen in Addison disease?", options: ["Hypernatremia and hypokalemia", "Hyponatremia and hyperkalemia", "Hypernatremia and hyperkalemia", "Hyponatremia and hypokalemia"], correctAnswer: 1, rationaleLong: "Addison disease (primary adrenal insufficiency) results in decreased aldosterone and cortisol production. Decreased aldosterone leads to sodium wasting (hyponatremia) and potassium retention (hyperkalemia). Other findings include hypoglycemia, hypotension, hyperpigmentation, and eosinophilia.", blueprintCategory: "Clinical Chemistry", subtopic: "Endocrine / Hormones", difficulty: 3, cognitiveLevel: "application", learningObjective: "Correlate electrolyte changes with adrenal disorders" },
  { stem: "What is the clinical significance of microalbumin testing?", options: ["Detection of nephrotic syndrome", "Early detection of diabetic nephropathy", "Diagnosis of multiple myeloma", "Screening for liver disease"], correctAnswer: 1, rationaleLong: "Microalbumin (albumin-to-creatinine ratio or timed urine collection) detects small amounts of albumin in urine (30-300 mg/day) that are not detected by routine dipstick. It is the earliest marker of diabetic nephropathy and is recommended annually for all diabetic patients. Early intervention can slow progression.", blueprintCategory: "Clinical Chemistry", subtopic: "Renal Function", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Understand microalbumin testing" },
  { stem: "A laboratory receives a specimen with a delta check flag for potassium (previous result 4.2 mEq/L, current result 6.8 mEq/L). What should the technologist do first?", options: ["Report the result as is", "Check the specimen for hemolysis", "Notify the physician immediately", "Repeat the test on the same specimen"], correctAnswer: 1, rationaleLong: "A delta check flag indicates a significant change from the patient's previous result. The most common preanalytical cause of falsely elevated potassium is hemolysis. The technologist should first check the specimen for hemolysis (visually and/or by hemolysis index). If hemolyzed, request a new specimen. If not hemolyzed, repeat the test and notify if confirmed.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 3, cognitiveLevel: "application", learningObjective: "Apply quality assurance procedures" },
  { stem: "Which of the following is a phase II (conjugation) reaction in drug metabolism?", options: ["Oxidation by cytochrome P450", "Reduction", "Hydrolysis", "Glucuronidation"], correctAnswer: 3, rationaleLong: "Drug metabolism occurs in two phases. Phase I reactions (oxidation, reduction, hydrolysis) modify the drug molecule, primarily through cytochrome P450 enzymes. Phase II reactions (conjugation) attach a polar group (glucuronic acid, sulfate, glutathione, acetyl, methyl) to make the drug more water-soluble for excretion. Glucuronidation is the most common Phase II reaction.", blueprintCategory: "Clinical Chemistry", subtopic: "Therapeutic Drug Monitoring", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Understand drug metabolism phases" },
  { stem: "Which specimen additive is an anticoagulant that works by chelating calcium?", options: ["Heparin", "EDTA", "Sodium fluoride", "Thrombin"], correctAnswer: 1, rationaleLong: "EDTA (ethylenediaminetetraacetic acid) prevents coagulation by chelating (binding) calcium ions, which are essential for the coagulation cascade. EDTA is the anticoagulant of choice for hematology testing. Heparin inhibits thrombin and is used for chemistry. Sodium fluoride is a glycolytic inhibitor, not an anticoagulant.", blueprintCategory: "Clinical Chemistry", subtopic: "Instrumentation (Spectrophotometry, ISE, HPLC)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know specimen additives and mechanisms" },
  { stem: "Direct ISE methods for sodium measurement are less affected by lipemia than indirect ISE because:", options: ["Direct ISE uses a different electrode", "Direct ISE measures undiluted specimens", "Lipemia does not affect sodium", "Direct ISE corrects for lipemia automatically"], correctAnswer: 1, rationaleLong: "Direct ISE methods measure ion activity in undiluted whole blood or plasma, so the volume displacement effect of lipemia does not apply. Indirect ISE methods dilute the sample, and lipemia occupies volume that displaces water, leading to falsely decreased electrolyte results (pseudohyponatremia). Direct ISE is preferred for lipemic specimens.", blueprintCategory: "Clinical Chemistry", subtopic: "Instrumentation (Spectrophotometry, ISE, HPLC)", difficulty: 4, cognitiveLevel: "analysis", learningObjective: "Compare direct and indirect ISE methods" },
  { stem: "Which stain is used to identify iron stores in bone marrow?", options: ["Wright stain", "Prussian blue (Perls) stain", "Periodic acid-Schiff (PAS)", "Sudan black B"], correctAnswer: 1, rationaleLong: "Prussian blue stain (Perls stain) detects iron (hemosiderin) in tissues and bone marrow. It is the gold standard for assessing iron stores. The reaction involves potassium ferrocyanide reacting with ferric iron to produce an insoluble blue pigment. Absence of stainable iron confirms iron deficiency.", blueprintCategory: "Clinical Chemistry", subtopic: "Proteins & Amino Acids", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know special stains for iron assessment" },
  { stem: "A patient has the following results: AST 35 U/L, ALT 32 U/L, ALP 520 U/L, GGT 380 U/L, total bilirubin 4.2 mg/dL, direct bilirubin 3.5 mg/dL. This pattern is most consistent with:", options: ["Hepatocellular disease", "Obstructive biliary disease", "Hemolytic disease", "Muscle injury"], correctAnswer: 1, rationaleLong: "The pattern shows disproportionately elevated ALP and GGT with relatively normal AST/ALT, elevated direct (conjugated) bilirubin, and elevated total bilirubin. This is the classic pattern of obstructive biliary disease (cholestatic pattern). The elevated GGT confirms the hepatobiliary origin of the elevated ALP (as opposed to bone disease).", blueprintCategory: "Clinical Chemistry", subtopic: "Liver Function", difficulty: 4, cognitiveLevel: "analysis", learningObjective: "Differentiate cholestatic from hepatocellular patterns" },
  { stem: "What is the purpose of the reagent blank in spectrophotometry?", options: ["To calibrate the wavelength", "To correct for absorbance by reagents alone", "To verify linearity", "To check for stray light"], correctAnswer: 1, rationaleLong: "The reagent blank contains all assay components except the patient sample. It is used to measure and subtract the absorbance contributed by the reagents themselves, ensuring that only the absorbance due to the analyte in the patient sample is measured. This corrects for background interference.", blueprintCategory: "Clinical Chemistry", subtopic: "Instrumentation (Spectrophotometry, ISE, HPLC)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Understand spectrophotometric blanking" },
  { stem: "Nephelometry measures:", options: ["Light absorbance", "Light scattering", "Fluorescence emission", "Electrical conductivity"], correctAnswer: 1, rationaleLong: "Nephelometry measures the intensity of light scattered by antigen-antibody complexes in solution. The amount of scattered light is proportional to the concentration of the protein being measured. Nephelometry is used for quantitation of specific proteins (immunoglobulins, complement, CRP, transferrin). It differs from turbidimetry, which measures decreased light transmission.", blueprintCategory: "Clinical Chemistry", subtopic: "Instrumentation (Spectrophotometry, ISE, HPLC)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know nephelometry principles" },
  { stem: "Carbamazepine therapeutic monitoring is important because:", options: ["It has no toxic effects", "It induces its own metabolism over time", "It does not cross the blood-brain barrier", "It has a very wide therapeutic range"], correctAnswer: 1, rationaleLong: "Carbamazepine is an autoinducer — it induces its own metabolism by upregulating hepatic CYP3A4 enzymes. This means that doses adequate initially may become subtherapeutic after 2-4 weeks. Therapeutic monitoring is essential to maintain therapeutic levels (4-12 mcg/mL) as the metabolism rate increases.", blueprintCategory: "Clinical Chemistry", subtopic: "Therapeutic Drug Monitoring", difficulty: 4, cognitiveLevel: "application", learningObjective: "Understand carbamazepine pharmacokinetics" },
  { stem: "Which of the following is NOT a function of the liver?", options: ["Synthesis of albumin", "Conjugation of bilirubin", "Production of erythropoietin", "Metabolism of drugs"], correctAnswer: 2, rationaleLong: "Erythropoietin (EPO) is primarily produced by the kidneys (peritubular cells), not the liver. The liver performs many functions including protein synthesis (albumin, clotting factors), bilirubin conjugation, drug metabolism, bile production, glycogen storage, and urea synthesis. In fetal life, the liver does produce EPO, but in adults, the kidneys are the primary source.", blueprintCategory: "Clinical Chemistry", subtopic: "Liver Function", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know liver functions" },
  { stem: "A QC result falls outside the 2 SD range on a Levey-Jennings chart but within 3 SD. According to Westgard rules, which rule is violated?", options: ["1-2s warning", "1-3s rejection", "2-2s rejection", "R-4s rejection"], correctAnswer: 0, rationaleLong: "The 1-2s rule is a warning rule, not a rejection rule. When a single QC result exceeds ±2 SD but is within ±3 SD, it is flagged as a warning to inspect the run more closely using additional Westgard rules (2-2s, R-4s, 4-1s, 10x). The 1-3s rule (any single QC exceeding ±3 SD) is a rejection rule.", blueprintCategory: "Clinical Chemistry", subtopic: "Instrumentation (Spectrophotometry, ISE, HPLC)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Apply Westgard QC rules" },
  { stem: "Which of the following would shift the oxyhemoglobin dissociation curve to the right?", options: ["Decreased temperature", "Decreased 2,3-DPG", "Decreased pH (acidosis)", "Increased CO exposure"], correctAnswer: 2, rationaleLong: "A rightward shift of the oxyhemoglobin dissociation curve means decreased oxygen affinity (hemoglobin releases oxygen more easily). Factors causing a right shift include: decreased pH (acidosis/Bohr effect), increased temperature, increased 2,3-DPG, and increased pCO2. Left shift occurs with the opposite conditions.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 3, cognitiveLevel: "application", learningObjective: "Understand oxyhemoglobin dissociation curve shifts" },
  { stem: "What does the term 'coefficient of variation (CV)' describe?", options: ["Accuracy of a method", "Precision expressed as a percentage", "Sensitivity of an assay", "Specificity of a test"], correctAnswer: 1, rationaleLong: "The coefficient of variation (CV) is a measure of precision (reproducibility) expressed as a percentage: CV = (SD / Mean) × 100. A lower CV indicates better precision. CV allows comparison of precision between different methods or analytes, regardless of the concentration level or units of measurement.", blueprintCategory: "Clinical Chemistry", subtopic: "Instrumentation (Spectrophotometry, ISE, HPLC)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Understand precision metrics" },
  { stem: "A laboratory performs method validation and finds the new method has a slope of 1.05 and y-intercept of -2.0 compared to the reference method. This indicates:", options: ["The new method has random error only", "The new method has a positive proportional bias and negative constant bias", "The methods agree perfectly", "The new method is more precise"], correctAnswer: 1, rationaleLong: "In method comparison, a slope ≠ 1.0 indicates proportional bias (the error changes with concentration). A slope of 1.05 means the new method reads about 5% higher than the reference at all concentrations (proportional bias). A y-intercept ≠ 0 indicates constant bias. The intercept of -2.0 means the new method reads 2 units lower at all concentrations (constant negative bias).", blueprintCategory: "Clinical Chemistry", subtopic: "Instrumentation (Spectrophotometry, ISE, HPLC)", difficulty: 4, cognitiveLevel: "analysis", learningObjective: "Interpret method comparison statistics" },
  { stem: "Glycated hemoglobin (HbA1c) testing is NOT reliable in patients with:", options: ["Type 2 diabetes", "Gestational diabetes", "Sickle cell disease", "Thyroid disorders"], correctAnswer: 2, rationaleLong: "HbA1c reflects average glucose over the RBC lifespan (~120 days). Any condition that alters RBC lifespan affects HbA1c reliability. Sickle cell disease causes shortened RBC survival, leading to falsely low HbA1c. Hemoglobin variants (HbS, HbC, HbE) may also interfere with certain HbA1c assay methods.", blueprintCategory: "Clinical Chemistry", subtopic: "Carbohydrates", difficulty: 3, cognitiveLevel: "application", learningObjective: "Know HbA1c limitations" },
  { stem: "Elevated homocysteine is a risk factor for:", options: ["Diabetes mellitus", "Cardiovascular disease", "Liver cirrhosis", "Renal tubular acidosis"], correctAnswer: 1, rationaleLong: "Elevated homocysteine (hyperhomocysteinemia) is an independent risk factor for cardiovascular disease, including coronary artery disease, stroke, and peripheral vascular disease. Homocysteine damages endothelium and promotes thrombosis. It can be lowered with folate, vitamin B6, and vitamin B12 supplementation.", blueprintCategory: "Clinical Chemistry", subtopic: "Proteins & Amino Acids", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know cardiovascular risk markers" },
  { stem: "A patient has high total T4 but normal free T4 and normal TSH. The most likely explanation is:", options: ["Hyperthyroidism", "Hypothyroidism", "Increased thyroxine-binding globulin", "Thyroid cancer"], correctAnswer: 2, rationaleLong: "Elevated total T4 with normal free T4 and normal TSH indicates euthyroid hyperthyroxinemia. The most common cause is elevated TBG (thyroxine-binding globulin), which increases total T4 but does not affect the free (unbound) hormone level. Common causes of elevated TBG include pregnancy, oral contraceptives, and estrogen therapy.", blueprintCategory: "Clinical Chemistry", subtopic: "Endocrine / Hormones", difficulty: 4, cognitiveLevel: "analysis", learningObjective: "Interpret discordant thyroid function results" },
  { stem: "Which of the following is the best marker for acute alcohol intoxication?", options: ["GGT", "Ethanol level", "CDT (carbohydrate-deficient transferrin)", "MCV"], correctAnswer: 1, rationaleLong: "Direct measurement of blood ethanol level is the best marker for acute alcohol intoxication. GGT and CDT are markers of chronic alcohol use. MCV may be elevated in chronic alcohol use due to folate deficiency. Legal intoxication in most US states is a blood alcohol level ≥80 mg/dL (0.08%).", blueprintCategory: "Clinical Chemistry", subtopic: "Toxicology", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Distinguish acute vs. chronic alcohol markers" },
  { stem: "Ceruloplasmin is decreased in:", options: ["Hemochromatosis", "Wilson disease", "Iron deficiency anemia", "Multiple myeloma"], correctAnswer: 1, rationaleLong: "Wilson disease is a genetic disorder of copper metabolism resulting in copper accumulation in the liver, brain, and other organs. Ceruloplasmin (copper-carrying protein) is characteristically decreased (<20 mg/dL) in most patients with Wilson disease. Other findings include elevated 24-hour urine copper, Kayser-Fleischer rings, and hepatic copper concentration >250 mcg/g.", blueprintCategory: "Clinical Chemistry", subtopic: "Proteins & Amino Acids", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know ceruloplasmin associations" },
  { stem: "Which of the following electrolytes is primarily intracellular?", options: ["Sodium", "Chloride", "Potassium", "Calcium"], correctAnswer: 2, rationaleLong: "Potassium is the major intracellular cation, with intracellular concentration approximately 150 mEq/L versus extracellular concentration of 3.5-5.0 mEq/L. Sodium is the major extracellular cation. This concentration gradient is maintained by the Na+/K+ ATPase pump. Hemolysis releases intracellular potassium, causing falsely elevated serum potassium.", blueprintCategory: "Clinical Chemistry", subtopic: "Electrolytes & Blood Gases", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know electrolyte distribution" },
  { stem: "Point-of-care testing for HbA1c uses which analytical principle?", options: ["Immunoturbidimetry or boronate affinity", "Flame photometry", "Atomic absorption", "Mass spectrometry"], correctAnswer: 0, rationaleLong: "Point-of-care HbA1c analyzers commonly use either immunoturbidimetric methods (antibody-based) or boronate affinity chromatography. Boronate affinity separates glycated from non-glycated hemoglobin based on the cis-diol groups present on glycated hemoglobin. These POCT methods must be NGSP-certified for accuracy.", blueprintCategory: "Clinical Chemistry", subtopic: "Carbohydrates", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know POCT analytical methods" },
  { stem: "Which of the following is most likely to cause an elevated serum amylase WITHOUT pancreatitis?", options: ["Hepatitis", "Parotitis (mumps)", "Myocardial infarction", "Anemia"], correctAnswer: 1, rationaleLong: "The salivary glands produce significant amounts of amylase (salivary isoenzyme S-type). Parotitis (inflammation of the parotid glands, as in mumps) causes release of salivary amylase into the blood, elevating total serum amylase without pancreatic involvement. Amylase isoenzyme analysis can differentiate salivary from pancreatic sources.", blueprintCategory: "Clinical Chemistry", subtopic: "Enzymes", difficulty: 3, cognitiveLevel: "application", learningObjective: "Identify non-pancreatic causes of elevated amylase" },
  { stem: "Which of the following analytes requires protection from light during transport?", options: ["Glucose", "Bilirubin", "Potassium", "Creatinine"], correctAnswer: 1, rationaleLong: "Bilirubin is photosensitive and decomposes when exposed to light (natural or fluorescent). Specimens for bilirubin measurement should be protected from light by wrapping in foil or using amber tubes. Significant degradation can occur within 1 hour of light exposure, leading to falsely decreased results.", blueprintCategory: "Clinical Chemistry", subtopic: "Liver Function", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know specimen handling requirements" },
];

const hematologyQuestions: MltQuestion[] = [
  { stem: "Which of the following RBC morphologies is characteristically associated with iron deficiency anemia?", options: ["Spherocytes", "Target cells", "Microcytic hypochromic cells", "Sickle cells"], correctAnswer: 2, rationaleLong: "Iron deficiency anemia is characterized by microcytic (small) and hypochromic (pale) red blood cells. Decreased iron leads to decreased hemoglobin synthesis, resulting in cells with less hemoglobin (hypochromia) and smaller volume (microcytosis). MCV <80 fL and MCH <27 pg are typical findings.", blueprintCategory: "Hematology", subtopic: "Anemias (Iron-deficiency, Megaloblastic, Hemolytic)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Associate RBC morphology with anemias" },
  { stem: "A CBC shows MCV 110 fL, MCH 38 pg, MCHC 34 g/dL. This is consistent with:", options: ["Iron deficiency anemia", "Thalassemia trait", "Megaloblastic anemia", "Anemia of chronic disease"], correctAnswer: 2, rationaleLong: "An MCV of 110 fL is macrocytic (normal 80-100 fL), and the elevated MCH is consistent with megaloblastic anemia. Megaloblastic anemia is caused by vitamin B12 or folate deficiency, which impairs DNA synthesis. The peripheral smear would show macro-ovalocytes and hypersegmented neutrophils.", blueprintCategory: "Hematology", subtopic: "Anemias (Iron-deficiency, Megaloblastic, Hemolytic)", difficulty: 2, cognitiveLevel: "application", learningObjective: "Classify anemias by RBC indices" },
  { stem: "Hypersegmented neutrophils (6+ lobes) are most commonly associated with:", options: ["Iron deficiency", "Vitamin B12 or folate deficiency", "Chronic myelogenous leukemia", "Bacterial infection"], correctAnswer: 1, rationaleLong: "Hypersegmented neutrophils (≥5 lobes in >5% of neutrophils, or any neutrophil with ≥6 lobes) are a hallmark finding of megaloblastic anemia caused by vitamin B12 (cobalamin) or folate deficiency. The impaired DNA synthesis affects nuclear maturation, leading to nuclear hypersegmentation.", blueprintCategory: "Hematology", subtopic: "Leukocytes (WBC Morphology & Disorders)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Recognize morphologic findings in megaloblastic anemia" },
  { stem: "The 'shift to the left' in a WBC differential refers to:", options: ["Increased lymphocytes", "Increased eosinophils", "Increased immature granulocytes (bands, metamyelocytes)", "Increased monocytes"], correctAnswer: 2, rationaleLong: "A 'left shift' refers to an increase in immature neutrophils (bands, metamyelocytes, myelocytes) in the peripheral blood. This indicates increased bone marrow production in response to acute infection, inflammation, or physiological stress. The term originates from the position of immature cells on the left side of the maturation schematic.", blueprintCategory: "Hematology", subtopic: "Leukocytes (WBC Morphology & Disorders)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Define left shift in WBC differential" },
  { stem: "Which of the following conditions is associated with an increased reticulocyte count?", options: ["Aplastic anemia", "Hemolytic anemia", "Iron deficiency anemia (untreated)", "Chronic renal failure"], correctAnswer: 1, rationaleLong: "Hemolytic anemia causes increased RBC destruction, which stimulates the bone marrow to increase production of reticulocytes (immature RBCs). An elevated reticulocyte count (>2%) indicates increased erythropoietic activity. In aplastic anemia and chronic renal failure, the reticulocyte count is decreased due to impaired production.", blueprintCategory: "Hematology", subtopic: "ESR & Reticulocyte Count", difficulty: 2, cognitiveLevel: "application", learningObjective: "Interpret reticulocyte count" },
  { stem: "A positive direct antiglobulin test (DAT) with spherocytes on the peripheral smear is characteristic of:", options: ["Hereditary spherocytosis", "Autoimmune hemolytic anemia", "G6PD deficiency", "Sickle cell disease"], correctAnswer: 1, rationaleLong: "Autoimmune hemolytic anemia (AIHA) is characterized by antibody-coated RBCs (positive DAT), spherocytes (from partial phagocytosis of antibody-coated cells), and evidence of hemolysis (elevated LD, bilirubin, decreased haptoglobin). Hereditary spherocytosis also has spherocytes but a negative DAT.", blueprintCategory: "Hematology", subtopic: "Anemias (Iron-deficiency, Megaloblastic, Hemolytic)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Differentiate causes of spherocytosis" },
  { stem: "Auer rods are pathognomonic for:", options: ["Acute lymphoblastic leukemia", "Acute myeloid leukemia", "Chronic lymphocytic leukemia", "Hairy cell leukemia"], correctAnswer: 1, rationaleLong: "Auer rods are pink-red, rod-shaped cytoplasmic inclusions composed of fused azurophilic (primary) granules. They are found exclusively in myeloid neoplasms and are pathognomonic for acute myeloid leukemia (AML). They are particularly common in AML-M3 (acute promyelocytic leukemia), where 'faggot cells' contain bundles of Auer rods.", blueprintCategory: "Hematology", subtopic: "Leukemias & Lymphomas", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Identify Auer rods and their significance" },
  { stem: "Which of the following is the most common type of leukemia in adults?", options: ["Acute lymphoblastic leukemia (ALL)", "Acute myeloid leukemia (AML)", "Chronic lymphocytic leukemia (CLL)", "Chronic myelogenous leukemia (CML)"], correctAnswer: 2, rationaleLong: "Chronic lymphocytic leukemia (CLL) is the most common leukemia in adults in Western countries. It typically presents in patients >60 years with lymphocytosis consisting of small, mature-appearing lymphocytes and smudge cells on the peripheral smear. ALL is most common in children.", blueprintCategory: "Hematology", subtopic: "Leukemias & Lymphomas", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know leukemia epidemiology" },
  { stem: "Smudge cells (basket cells) on a peripheral blood smear are characteristic of:", options: ["AML", "CLL", "CML", "ALL"], correctAnswer: 1, rationaleLong: "Smudge cells (also called basket cells) are fragile lymphocytes that rupture during blood smear preparation. They are characteristic of chronic lymphocytic leukemia (CLL). The lymphocytes in CLL are fragile due to their mature but abnormal nature. Adding a drop of albumin to the blood before making the smear can reduce smudge cell formation.", blueprintCategory: "Hematology", subtopic: "Leukemias & Lymphomas", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Identify smudge cells and their association" },
  { stem: "The Philadelphia chromosome [t(9;22)] is associated with:", options: ["AML-M3", "CML", "CLL", "ALL (adult)"], correctAnswer: 1, rationaleLong: "The Philadelphia chromosome results from a reciprocal translocation between chromosomes 9 and 22 [t(9;22)], creating the BCR-ABL1 fusion gene. It is the defining feature of chronic myelogenous leukemia (CML) and is present in >95% of CML cases. The BCR-ABL1 protein has constitutive tyrosine kinase activity, which is the target of imatinib (Gleevec).", blueprintCategory: "Hematology", subtopic: "Leukemias & Lymphomas", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know cytogenetic markers of leukemias" },
  { stem: "What is the normal absolute neutrophil count (ANC) in adults?", options: ["500-1,000/μL", "1,500-8,000/μL", "10,000-15,000/μL", "20,000-30,000/μL"], correctAnswer: 1, rationaleLong: "The normal absolute neutrophil count is approximately 1,500-8,000/μL (1.5-8.0 × 10⁹/L). Neutropenia is defined as ANC <1,500/μL, with severe neutropenia <500/μL. ANC is calculated as: WBC × (% segs + % bands) / 100. Severe neutropenia increases infection risk significantly.", blueprintCategory: "Hematology", subtopic: "Leukocytes (WBC Morphology & Disorders)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know normal ANC values" },
  { stem: "A patient has WBC 15,000/μL with 70% segs and 5% bands. What is the absolute neutrophil count?", options: ["7,500/μL", "10,500/μL", "11,250/μL", "15,000/μL"], correctAnswer: 2, rationaleLong: "ANC = WBC × (% segs + % bands) / 100 = 15,000 × (70 + 5) / 100 = 15,000 × 0.75 = 11,250/μL. This is within the normal range. An elevated ANC (neutrophilia) is seen with bacterial infections, inflammation, stress, and steroid use.", blueprintCategory: "Hematology", subtopic: "Leukocytes (WBC Morphology & Disorders)", difficulty: 2, cognitiveLevel: "application", learningObjective: "Calculate ANC" },
  { stem: "Howell-Jolly bodies are:", options: ["DNA remnants in RBCs", "Iron granules in RBCs", "Denatured hemoglobin", "RNA remnants in reticulocytes"], correctAnswer: 0, rationaleLong: "Howell-Jolly bodies are small, round, dark-staining nuclear remnants (DNA fragments) found in red blood cells. They are normally removed by the spleen. Their presence indicates splenic dysfunction or asplenia (surgical removal, sickle cell disease with autosplenectomy, or congenital asplenia).", blueprintCategory: "Hematology", subtopic: "Erythrocytes (RBC Morphology & Disorders)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Identify RBC inclusions" },
  { stem: "Heinz bodies are best visualized with which stain?", options: ["Wright stain", "Crystal violet or brilliant cresyl blue", "Prussian blue stain", "New methylene blue"], correctAnswer: 1, rationaleLong: "Heinz bodies are inclusions of denatured (oxidized) hemoglobin that adhere to the RBC membrane. They are NOT visible on Wright-stained smears and require supravital staining with crystal violet or brilliant cresyl blue. Heinz bodies are seen in G6PD deficiency, unstable hemoglobins, and oxidant drug exposure.", blueprintCategory: "Hematology", subtopic: "Erythrocytes (RBC Morphology & Disorders)", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know staining methods for RBC inclusions" },
  { stem: "Which of the following is characteristic of sickle cell disease?", options: ["Microcytic hypochromic anemia", "Normocytic hemolytic anemia with sickle cells", "Macrocytic anemia with target cells", "Iron-overload anemia"], correctAnswer: 1, rationaleLong: "Sickle cell disease (HbSS) is a normocytic (or slightly macrocytic) hemolytic anemia caused by a point mutation in the beta-globin gene. The peripheral smear shows sickle cells, target cells, Howell-Jolly bodies (functional asplenia), and nucleated RBCs. Hemoglobin electrophoresis shows predominantly HbS.", blueprintCategory: "Hematology", subtopic: "Hemoglobin & Hemoglobinopathies", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know laboratory findings in sickle cell disease" },
  { stem: "Hemoglobin electrophoresis at alkaline pH separates hemoglobins in which order (fastest to slowest)?", options: ["A, F, S, C", "C, S, F, A", "A, F, S, C (anode to cathode)", "S, C, A, F"], correctAnswer: 2, rationaleLong: "At alkaline pH (cellulose acetate), hemoglobins migrate toward the anode in the following order from fastest to slowest: A, F, S, C (and A2). A useful mnemonic is 'All Fools Stumble and Crumble.' HbS and HbD co-migrate, as do HbC and HbE. Citrate agar electrophoresis at acid pH is used to resolve these.", blueprintCategory: "Hematology", subtopic: "Hemoglobin & Hemoglobinopathies", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know hemoglobin electrophoresis migration patterns" },
  { stem: "Target cells are associated with all of the following EXCEPT:", options: ["Thalassemia", "Iron deficiency anemia", "Liver disease", "Hereditary spherocytosis"], correctAnswer: 3, rationaleLong: "Target cells (codocytes) are associated with thalassemia, hemoglobin C disease, liver disease, iron deficiency anemia, and post-splenectomy states. Hereditary spherocytosis produces spherocytes, not target cells. Target cells form when there is an increase in the surface area-to-volume ratio of the RBC.", blueprintCategory: "Hematology", subtopic: "Erythrocytes (RBC Morphology & Disorders)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Associate target cells with clinical conditions" },
  { stem: "Which RBC inclusion is associated with lead poisoning?", options: ["Howell-Jolly bodies", "Pappenheimer bodies", "Basophilic stippling", "Heinz bodies"], correctAnswer: 2, rationaleLong: "Basophilic stippling (aggregated ribosomes) is characteristically seen in lead poisoning. Lead inhibits several enzymes in the heme synthesis pathway, including delta-aminolevulinic acid dehydratase and ferrochelatase. Other findings in lead poisoning include elevated free erythrocyte protoporphyrin, elevated blood lead level, and ringed sideroblasts.", blueprintCategory: "Hematology", subtopic: "Erythrocytes (RBC Morphology & Disorders)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know RBC inclusions and their associations" },
  { stem: "Schistocytes (fragmented RBCs) are most commonly associated with:", options: ["Iron deficiency anemia", "Microangiopathic hemolytic anemia", "Megaloblastic anemia", "Sickle cell trait"], correctAnswer: 1, rationaleLong: "Schistocytes are fragmented red blood cells caused by mechanical shearing. They are the hallmark of microangiopathic hemolytic anemia (MAHA), seen in DIC, TTP, HUS, malignant hypertension, and damaged prosthetic heart valves. The presence of schistocytes with thrombocytopenia should raise suspicion for TTP or DIC.", blueprintCategory: "Hematology", subtopic: "Anemias (Iron-deficiency, Megaloblastic, Hemolytic)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Associate schistocytes with clinical conditions" },
  { stem: "The ESR (erythrocyte sedimentation rate) is elevated in all of the following EXCEPT:", options: ["Multiple myeloma", "Pregnancy", "Polycythemia vera", "Rheumatoid arthritis"], correctAnswer: 2, rationaleLong: "The ESR measures the rate at which RBCs settle in a vertical tube. It is elevated in inflammatory conditions, pregnancy, anemia, and paraproteinemias (multiple myeloma). Polycythemia vera (increased RBC mass) causes a decreased ESR because the increased number of RBCs settle more slowly.", blueprintCategory: "Hematology", subtopic: "ESR & Reticulocyte Count", difficulty: 2, cognitiveLevel: "application", learningObjective: "Know conditions affecting ESR" },
  { stem: "Rouleaux formation on a peripheral smear is associated with:", options: ["Iron deficiency", "Multiple myeloma", "Sickle cell disease", "Thalassemia"], correctAnswer: 1, rationaleLong: "Rouleaux formation (stacking of RBCs like coins) is caused by elevated levels of fibrinogen or immunoglobulins that decrease the negative charge (zeta potential) of RBCs. It is classically associated with multiple myeloma (elevated immunoglobulins), Waldenström macroglobulinemia, and chronic inflammatory conditions.", blueprintCategory: "Hematology", subtopic: "Erythrocytes (RBC Morphology & Disorders)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Recognize rouleaux formation" },
  { stem: "An automated hematology analyzer flags a specimen for WBC review. The histogram shows two peaks in the lymphocyte region. The most likely cause is:", options: ["Bacterial infection", "Nucleated red blood cells (NRBCs)", "Platelet clumping", "Cold agglutinins"], correctAnswer: 1, rationaleLong: "Nucleated red blood cells (NRBCs) are similar in size to lymphocytes and may be counted as WBCs by some hematology analyzers, creating an abnormal histogram pattern. This causes a falsely elevated WBC count. The analyzer flags this for manual review and a corrected WBC count should be performed.", blueprintCategory: "Hematology", subtopic: "Automated Hematology Analyzers", difficulty: 3, cognitiveLevel: "application", learningObjective: "Troubleshoot hematology analyzer flags" },
  { stem: "How should the WBC count be corrected when nucleated RBCs are present?", options: ["Add the NRBC count to the total WBC", "Corrected WBC = (Observed WBC × 100) / (100 + NRBC/100 WBCs)", "Subtract NRBCs from the WBC count", "No correction is needed"], correctAnswer: 1, rationaleLong: "When NRBCs are present, the corrected WBC count is calculated as: Corrected WBC = (Observed WBC × 100) / (100 + # NRBCs per 100 WBCs). For example, if the observed WBC is 15,000 and 50 NRBCs per 100 WBCs are counted: Corrected WBC = (15,000 × 100) / (100 + 50) = 10,000/μL.", blueprintCategory: "Hematology", subtopic: "Automated Hematology Analyzers", difficulty: 3, cognitiveLevel: "application", learningObjective: "Calculate corrected WBC count" },
  { stem: "Toxic granulation in neutrophils indicates:", options: ["Allergic reaction", "Severe bacterial infection or inflammation", "Chronic lymphocytic leukemia", "Vitamin B12 deficiency"], correctAnswer: 1, rationaleLong: "Toxic granulation refers to dark, coarse azurophilic granules in neutrophils that result from retained primary granules during accelerated granulopoiesis. It indicates a severe inflammatory or infectious process. Other toxic changes include Döhle bodies (blue cytoplasmic RNA inclusions) and cytoplasmic vacuolization.", blueprintCategory: "Hematology", subtopic: "Leukocytes (WBC Morphology & Disorders)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Recognize toxic changes in neutrophils" },
  { stem: "Reed-Sternberg cells are diagnostic of:", options: ["Non-Hodgkin lymphoma", "Hodgkin lymphoma", "Acute myeloid leukemia", "Chronic myelogenous leukemia"], correctAnswer: 1, rationaleLong: "Reed-Sternberg (RS) cells are large, binucleated or multinucleated cells with prominent nucleoli ('owl-eye' appearance) that are the hallmark of classic Hodgkin lymphoma. They are derived from germinal center B cells. RS cells are typically CD15+ and CD30+. Their presence is required for diagnosis of Hodgkin lymphoma.", blueprintCategory: "Hematology", subtopic: "Leukemias & Lymphomas", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know Reed-Sternberg cells and Hodgkin lymphoma" },
  { stem: "A patient with pancytopenia and a dry tap on bone marrow aspiration should be evaluated for:", options: ["Iron deficiency anemia", "Chronic lymphocytic leukemia", "Aplastic anemia or marrow infiltration", "Polycythemia vera"], correctAnswer: 2, rationaleLong: "A 'dry tap' (inability to aspirate bone marrow) combined with pancytopenia suggests either aplastic anemia (where the marrow is replaced by fat) or marrow infiltration (fibrosis, metastatic cancer, hairy cell leukemia). A bone marrow biopsy (trephine) is essential to evaluate cellularity and architecture.", blueprintCategory: "Hematology", subtopic: "Hematopoiesis", difficulty: 3, cognitiveLevel: "application", learningObjective: "Evaluate bone marrow failure" },
  { stem: "The myeloid-to-erythroid (M:E) ratio in normal adult bone marrow is approximately:", options: ["1:1", "2:1 to 4:1", "6:1 to 8:1", "10:1"], correctAnswer: 1, rationaleLong: "The normal M:E ratio in adult bone marrow is approximately 2:1 to 4:1 (some references 3:1 to 4:1). An increased M:E ratio is seen in myeloid hyperplasia (infections, CML). A decreased M:E ratio indicates erythroid hyperplasia (hemolytic anemia, hemorrhage) or myeloid hypoplasia.", blueprintCategory: "Hematology", subtopic: "Hematopoiesis", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know normal bone marrow M:E ratio" },
  { stem: "Which of the following is a characteristic finding in thalassemia major?", options: ["Elevated HbA1c", "Elevated HbF", "Elevated HbS", "Elevated HbA2 only"], correctAnswer: 1, rationaleLong: "Beta-thalassemia major (Cooley anemia) results from absence or severe reduction of beta-globin chain synthesis. This leads to compensatory increase in HbF (alpha2/gamma2) production. HbF levels can be 60-90% in thalassemia major. The peripheral smear shows severe microcytic hypochromic anemia with target cells, NRBCs, and basophilic stippling.", blueprintCategory: "Hematology", subtopic: "Hemoglobin & Hemoglobinopathies", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know hemoglobin findings in thalassemia" },
  { stem: "G6PD deficiency results in hemolytic anemia triggered by:", options: ["Cold temperatures", "Oxidant drugs and infections", "Physical exercise", "High altitude"], correctAnswer: 1, rationaleLong: "G6PD (glucose-6-phosphate dehydrogenase) deficiency impairs the hexose monophosphate shunt, which generates NADPH for glutathione reduction. Without adequate reduced glutathione, RBCs cannot protect hemoglobin from oxidative damage. Triggers include oxidant drugs (primaquine, sulfonamides, dapsone), fava beans, and infections.", blueprintCategory: "Hematology", subtopic: "Anemias (Iron-deficiency, Megaloblastic, Hemolytic)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know G6PD deficiency triggers" },
  { stem: "What is the normal percentage of reticulocytes in peripheral blood?", options: ["0.1-0.5%", "0.5-2.0%", "3.0-5.0%", "5.0-10.0%"], correctAnswer: 1, rationaleLong: "The normal reticulocyte percentage in peripheral blood is 0.5-2.0% (approximately 25,000-85,000/μL absolute). Reticulocytes are immature RBCs that contain residual RNA (visible with supravital stains like new methylene blue). The reticulocyte count reflects bone marrow erythropoietic activity.", blueprintCategory: "Hematology", subtopic: "ESR & Reticulocyte Count", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know normal reticulocyte values" },
  { stem: "Reticulocytes are identified using which stain?", options: ["Wright stain", "Prussian blue stain", "New methylene blue (supravital stain)", "Giemsa stain"], correctAnswer: 2, rationaleLong: "Reticulocytes are identified using supravital stains such as new methylene blue or brilliant cresyl blue, which precipitate the residual RNA into a visible reticulum. Wright stain shows reticulocytes as polychromatic (blue-gray) cells due to the RNA content, but does not allow precise counting.", blueprintCategory: "Hematology", subtopic: "ESR & Reticulocyte Count", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know reticulocyte staining method" },
  { stem: "A 100-cell manual WBC differential shows: segs 65%, bands 8%, lymphocytes 18%, monocytes 6%, eosinophils 2%, basophils 1%. With a WBC of 12,000/μL, what is the absolute lymphocyte count?", options: ["1,800/μL", "2,160/μL", "2,400/μL", "7,800/μL"], correctAnswer: 1, rationaleLong: "Absolute lymphocyte count = WBC × (% lymphocytes / 100) = 12,000 × 0.18 = 2,160/μL. Absolute counts are more clinically meaningful than percentages because they account for the total WBC count. Normal absolute lymphocyte count is 1,000-4,000/μL.", blueprintCategory: "Hematology", subtopic: "Manual Differential", difficulty: 2, cognitiveLevel: "application", learningObjective: "Calculate absolute cell counts" },
  { stem: "Which of the following is the proper area of a blood smear to perform a differential count?", options: ["The thick area near the drop of blood", "The feathered edge", "The thin monolayer area where RBCs barely touch", "Any area of the smear"], correctAnswer: 2, rationaleLong: "The manual differential should be performed in the thin monolayer area of the smear where RBCs are evenly distributed and barely touching each other. The thick area has too many overlapping cells. The feathered edge tends to concentrate large cells (monocytes, abnormal cells) and distort morphology.", blueprintCategory: "Hematology", subtopic: "Peripheral Blood Smear Evaluation", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know proper blood smear evaluation technique" },
  { stem: "Döhle bodies are:", options: ["Iron inclusions in neutrophils", "Blue-gray cytoplasmic inclusions of RNA in neutrophils", "Nuclear remnants in erythrocytes", "Platelet granule aggregates"], correctAnswer: 1, rationaleLong: "Döhle bodies are pale blue-gray cytoplasmic inclusions composed of rough endoplasmic reticulum (RNA) found in neutrophils. They are a toxic change seen in severe infections, burns, pregnancy, and May-Hegglin anomaly. They are typically found at the periphery of the cell and may be subtle on Wright-stained smears.", blueprintCategory: "Hematology", subtopic: "Leukocytes (WBC Morphology & Disorders)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Identify Döhle bodies" },
  { stem: "Which of the following best describes eosinophilia?", options: ["Absolute eosinophil count >500/μL", "Relative eosinophils >1%", "Absolute eosinophil count >100/μL", "Eosinophils seen in bone marrow only"], correctAnswer: 0, rationaleLong: "Eosinophilia is defined as an absolute eosinophil count >500/μL (some references use >450/μL). Common causes include allergic reactions, parasitic infections, drug reactions, asthma, and certain autoimmune diseases. Marked eosinophilia (>1,500/μL) can cause tissue damage (hypereosinophilic syndrome).", blueprintCategory: "Hematology", subtopic: "Leukocytes (WBC Morphology & Disorders)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Define eosinophilia" },
  { stem: "Atypical lymphocytes (reactive lymphocytes) are most commonly seen in:", options: ["Chronic lymphocytic leukemia", "Infectious mononucleosis", "Iron deficiency anemia", "Bacterial sepsis"], correctAnswer: 1, rationaleLong: "Atypical (reactive) lymphocytes are large lymphocytes with abundant, often vacuolated cytoplasm that may mold around adjacent RBCs. They are most commonly associated with infectious mononucleosis (EBV infection) but can also be seen in CMV, hepatitis, drug reactions, and other viral infections. They represent activated T lymphocytes.", blueprintCategory: "Hematology", subtopic: "Leukocytes (WBC Morphology & Disorders)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Associate atypical lymphocytes with clinical conditions" },
  { stem: "Pelger-Huët anomaly is characterized by:", options: ["Hypersegmented neutrophils", "Hyposegmented neutrophils (bilobed)", "Giant platelets", "Abnormal eosinophil granulation"], correctAnswer: 1, rationaleLong: "Pelger-Huët anomaly is a benign autosomal dominant condition characterized by hyposegmented neutrophils, most commonly bilobed ('pince-nez' appearance). Nuclear function is normal. An acquired form (pseudo-Pelger-Huët) occurs in MDS, AML, and severe infections. It is important to distinguish this from a left shift.", blueprintCategory: "Hematology", subtopic: "Leukocytes (WBC Morphology & Disorders)", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Recognize Pelger-Huët anomaly" },
  { stem: "The most common cause of microcytic anemia worldwide is:", options: ["Vitamin B12 deficiency", "Iron deficiency", "Folate deficiency", "Sideroblastic anemia"], correctAnswer: 1, rationaleLong: "Iron deficiency is the most common cause of anemia worldwide and the most common cause of microcytic anemia. Causes include inadequate dietary intake, blood loss (menstruation, GI bleeding), increased requirements (pregnancy), and malabsorption. Laboratory findings include low ferritin, low iron, high TIBC, and low transferrin saturation.", blueprintCategory: "Hematology", subtopic: "Anemias (Iron-deficiency, Megaloblastic, Hemolytic)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know the most common cause of microcytic anemia" },
  { stem: "An EDTA specimen shows platelet clumping. The platelet count will be:", options: ["Falsely elevated", "Falsely decreased", "Unaffected", "Indeterminate"], correctAnswer: 1, rationaleLong: "Platelet clumping causes a falsely decreased platelet count because the automated analyzer counts clumps as single events or does not count them at all. EDTA-dependent pseudothrombocytopenia is caused by antibodies that bind to platelet glycoprotein IIb/IIIa in the presence of EDTA. Recollection in sodium citrate can resolve this.", blueprintCategory: "Hematology", subtopic: "Platelets & Megakaryocytes", difficulty: 2, cognitiveLevel: "application", learningObjective: "Troubleshoot spurious platelet counts" },
  { stem: "A patient has a platelet count of 45,000/μL. This condition is called:", options: ["Thrombocytosis", "Thrombocytopenia", "Thrombocythemia", "Pancytopenia"], correctAnswer: 1, rationaleLong: "Thrombocytopenia is defined as a platelet count <150,000/μL. A count of 45,000/μL is moderate thrombocytopenia. Spontaneous bleeding typically does not occur until platelets fall below 20,000/μL. Causes include ITP, DIC, TTP/HUS, medications, bone marrow failure, and hypersplenism.", blueprintCategory: "Hematology", subtopic: "Platelets & Megakaryocytes", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Define thrombocytopenia" },
  { stem: "Which of the following would cause a falsely elevated MCV?", options: ["Iron deficiency", "Cold agglutinins", "Thalassemia", "Lead poisoning"], correctAnswer: 1, rationaleLong: "Cold agglutinins cause RBCs to clump at room temperature. Automated analyzers measure clumps as single, large particles, resulting in falsely elevated MCV and falsely decreased RBC count. The MCH and MCHC may also be affected. Warming the specimen to 37°C before analysis resolves this artifact.", blueprintCategory: "Hematology", subtopic: "Automated Hematology Analyzers", difficulty: 3, cognitiveLevel: "application", learningObjective: "Identify causes of spurious MCV" },
  { stem: "Which stain is used in the manual reticulocyte count?", options: ["Wright-Giemsa", "New methylene blue", "Prussian blue", "Sudan black B"], correctAnswer: 1, rationaleLong: "New methylene blue is a supravital stain that precipitates residual ribosomal RNA in reticulocytes, forming a visible blue reticulum or filamentous network. The stain is mixed with blood, incubated briefly, and then a smear is made. At least 1,000 RBCs are counted to determine the percentage of reticulocytes.", blueprintCategory: "Hematology", subtopic: "ESR & Reticulocyte Count", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know reticulocyte staining procedure" },
  { stem: "An elevated red cell distribution width (RDW) with a low MCV is most suggestive of:", options: ["Beta-thalassemia trait", "Iron deficiency anemia", "Anemia of chronic disease", "Alpha-thalassemia trait"], correctAnswer: 1, rationaleLong: "Iron deficiency anemia shows a microcytic anemia with high RDW (reflecting anisocytosis — variation in RBC size). Thalassemia trait typically has a low MCV but normal RDW (uniform small cells). This distinction (RDW elevated in iron deficiency, normal in thalassemia) is a useful screening tool, though not definitive.", blueprintCategory: "Hematology", subtopic: "Anemias (Iron-deficiency, Megaloblastic, Hemolytic)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Use RDW to differentiate microcytic anemias" },
  { stem: "Which of the following is the most important safety precaution when handling blood specimens?", options: ["Wearing a lab coat only", "Using Standard Precautions (treating all specimens as potentially infectious)", "Wearing goggles only for large specimens", "Handwashing after the shift is complete"], correctAnswer: 1, rationaleLong: "Standard Precautions require that all human blood and body fluids be treated as potentially infectious. This includes wearing appropriate PPE (gloves, lab coat, face protection when splash risk exists), proper hand hygiene, safe needle handling, and proper decontamination. This approach eliminates the need to identify specific infectious patients.", blueprintCategory: "Hematology", subtopic: "Peripheral Blood Smear Evaluation", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know laboratory safety precautions" },
  { stem: "A bone marrow aspirate shows >20% blasts. This finding is most consistent with:", options: ["Myelodysplastic syndrome", "Acute leukemia", "Chronic leukemia", "Reactive marrow"], correctAnswer: 1, rationaleLong: "A blast percentage ≥20% in the bone marrow or peripheral blood is the WHO diagnostic criterion for acute leukemia (either AML or ALL). MDS is defined by blasts <20% with dysplastic features. CML has <20% blasts in chronic phase. The specific type of acute leukemia is determined by immunophenotyping, cytogenetics, and morphology.", blueprintCategory: "Hematology", subtopic: "Leukemias & Lymphomas", difficulty: 2, cognitiveLevel: "application", learningObjective: "Know diagnostic criteria for acute leukemia" },
  { stem: "In which condition is the osmotic fragility test increased (cells lyse in less hypotonic solutions)?", options: ["Iron deficiency anemia", "Hereditary spherocytosis", "Thalassemia", "Sickle cell disease"], correctAnswer: 1, rationaleLong: "Hereditary spherocytosis (HS) produces spherocytes that have a decreased surface area-to-volume ratio. These cells cannot swell as much as normal biconcave discs before lysing, so they have increased osmotic fragility (lyse in less hypotonic solutions). Thalassemia and iron deficiency show decreased osmotic fragility (target cells resist lysis).", blueprintCategory: "Hematology", subtopic: "Anemias (Iron-deficiency, Megaloblastic, Hemolytic)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Interpret osmotic fragility test" },
  { stem: "Acute promyelocytic leukemia (APL, AML-M3) is associated with which chromosomal translocation?", options: ["t(9;22)", "t(15;17)", "t(8;21)", "t(8;14)"], correctAnswer: 1, rationaleLong: "Acute promyelocytic leukemia (APL) is associated with the translocation t(15;17), which creates the PML-RARA fusion gene. This translocation is diagnostically definitive and has therapeutic implications: APL responds to all-trans retinoic acid (ATRA) therapy. APL commonly presents with DIC, and prompt diagnosis is critical.", blueprintCategory: "Hematology", subtopic: "Leukemias & Lymphomas", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know cytogenetic markers of AML subtypes" },
  { stem: "Which of the following cells is the precursor to all blood cells?", options: ["Myeloblast", "Pluripotent hematopoietic stem cell", "Proerythroblast", "Monoblast"], correctAnswer: 1, rationaleLong: "The pluripotent hematopoietic stem cell (HSC) is the common precursor for all blood cell lineages. It gives rise to the myeloid stem cell (which produces RBCs, granulocytes, monocytes, and platelets) and the lymphoid stem cell (which produces T cells, B cells, and NK cells). HSCs reside in the bone marrow.", blueprintCategory: "Hematology", subtopic: "Hematopoiesis", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know hematopoietic stem cell hierarchy" },
  { stem: "Pappenheimer bodies in RBCs contain:", options: ["DNA", "RNA", "Iron (siderotic granules)", "Denatured hemoglobin"], correctAnswer: 2, rationaleLong: "Pappenheimer bodies are iron-containing inclusions (siderotic granules) visible on Wright stain as small, irregular, blue-purple clusters, usually at the periphery of the RBC. They are confirmed by Prussian blue staining. They are seen in sideroblastic anemia, post-splenectomy, hemolytic anemias, and thalassemia.", blueprintCategory: "Hematology", subtopic: "Erythrocytes (RBC Morphology & Disorders)", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Identify Pappenheimer bodies" },
  { stem: "A patient with chronic kidney disease has normocytic normochromic anemia. The most likely cause is:", options: ["Iron deficiency", "Vitamin B12 deficiency", "Decreased erythropoietin production", "Folate deficiency"], correctAnswer: 2, rationaleLong: "Chronic kidney disease leads to decreased production of erythropoietin (EPO) by the peritubular cells of the kidneys. This results in decreased RBC production and normocytic normochromic anemia. Treatment is with recombinant EPO (erythropoiesis-stimulating agents). Iron stores should be adequate before starting EPO therapy.", blueprintCategory: "Hematology", subtopic: "Anemias (Iron-deficiency, Megaloblastic, Hemolytic)", difficulty: 2, cognitiveLevel: "application", learningObjective: "Understand anemia of CKD" },
  { stem: "Which of the following is the most sensitive test for detecting hemolysis?", options: ["Total bilirubin", "Haptoglobin", "LDH", "Reticulocyte count"], correctAnswer: 1, rationaleLong: "Haptoglobin is the most sensitive marker for intravascular hemolysis. It binds free hemoglobin released from lysed RBCs, and the complex is cleared by the liver. A decreased or absent haptoglobin level indicates hemolysis. Other hemolysis markers include elevated LDH, elevated indirect bilirubin, and increased reticulocyte count.", blueprintCategory: "Hematology", subtopic: "Anemias (Iron-deficiency, Megaloblastic, Hemolytic)", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know hemolysis markers" },
  { stem: "Teardrop cells (dacryocytes) are most commonly associated with:", options: ["Iron deficiency anemia", "Myelofibrosis", "Sickle cell disease", "Hereditary spherocytosis"], correctAnswer: 1, rationaleLong: "Teardrop cells (dacryocytes) are characteristically associated with myelofibrosis and other conditions involving bone marrow infiltration (myelophthisis). They form when RBCs are squeezed through fibrotic marrow. Teardrop cells are also seen in thalassemia, severe iron deficiency, and megaloblastic anemia.", blueprintCategory: "Hematology", subtopic: "Erythrocytes (RBC Morphology & Disorders)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Associate teardrop cells with conditions" },
  { stem: "Hairy cell leukemia is best identified by which cytochemical stain?", options: ["Myeloperoxidase", "TRAP (tartrate-resistant acid phosphatase)", "Sudan black B", "Periodic acid-Schiff"], correctAnswer: 1, rationaleLong: "Hairy cell leukemia (HCL) cells are characteristically positive for TRAP (tartrate-resistant acid phosphatase). HCL is a B-cell neoplasm with distinctive hairy cytoplasmic projections. Flow cytometry shows CD19+, CD20+, CD25+, CD103+, and CD11c+. HCL often causes pancytopenia and splenomegaly with a 'dry tap' on aspiration.", blueprintCategory: "Hematology", subtopic: "Leukemias & Lymphomas", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know cytochemical markers for leukemia classification" },
  { stem: "Which type of hemoglobin is increased in beta-thalassemia trait?", options: ["HbA", "HbA2", "HbF", "HbS"], correctAnswer: 1, rationaleLong: "Beta-thalassemia trait (minor) shows a mild microcytic anemia with elevated HbA2 (>3.5%, usually 4-8%). This is the key diagnostic finding on hemoglobin electrophoresis. HbF may be mildly elevated. The increased HbA2 results from excess alpha chains pairing with delta chains when beta chain production is reduced.", blueprintCategory: "Hematology", subtopic: "Hemoglobin & Hemoglobinopathies", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know hemoglobin findings in thalassemia trait" },
];

const hemostasisQuestions: MltQuestion[] = [
  { stem: "The prothrombin time (PT) evaluates which coagulation pathway?", options: ["Intrinsic pathway", "Extrinsic and common pathway", "Contact activation pathway only", "Fibrinolytic pathway"], correctAnswer: 1, rationaleLong: "The PT evaluates the extrinsic pathway (Factor VII) and the common pathway (Factors X, V, II/prothrombin, and fibrinogen). The reagent contains tissue thromboplastin (tissue factor) and calcium. PT is prolonged in vitamin K deficiency, warfarin therapy, liver disease, and deficiency of factors VII, X, V, II, or fibrinogen.", blueprintCategory: "Hemostasis / Coagulation", subtopic: "PT / INR", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know which pathway PT evaluates" },
  { stem: "The aPTT evaluates which coagulation pathway?", options: ["Extrinsic pathway", "Intrinsic and common pathway", "Fibrinolytic system", "Platelet function"], correctAnswer: 1, rationaleLong: "The aPTT evaluates the intrinsic pathway (Factors XII, XI, IX, VIII) and the common pathway (Factors X, V, II, fibrinogen). The reagent contains a contact activator (kaolin, silica, or ellagic acid), phospholipid, and calcium. aPTT monitors heparin therapy and detects factor deficiencies and lupus anticoagulant.", blueprintCategory: "Hemostasis / Coagulation", subtopic: "aPTT", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know which pathway aPTT evaluates" },
  { stem: "Both PT and aPTT are prolonged. Which factor deficiency is most likely?", options: ["Factor VIII", "Factor VII", "Factor X", "Factor XII"], correctAnswer: 2, rationaleLong: "Factor X is part of the common pathway, shared by both PT and aPTT. Deficiency of common pathway factors (X, V, II, fibrinogen) prolongs both tests. Factor VIII deficiency (hemophilia A) prolongs only the aPTT. Factor VII deficiency prolongs only the PT. Factor XII deficiency prolongs the aPTT but does not cause clinical bleeding.", blueprintCategory: "Hemostasis / Coagulation", subtopic: "Coagulation Cascade (Intrinsic, Extrinsic, Common)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Localize coagulation defects using PT and aPTT" },
  { stem: "D-dimer is elevated in which condition?", options: ["Hemophilia A", "Von Willebrand disease", "DIC (disseminated intravascular coagulation)", "Platelet storage pool disease"], correctAnswer: 2, rationaleLong: "D-dimer is a fibrin degradation product (FDP) formed when cross-linked fibrin is broken down by plasmin. Elevated D-dimer indicates both thrombin generation (fibrin formation) and fibrinolysis. It is elevated in DIC, DVT, PE, post-surgical states, and other conditions with ongoing coagulation and fibrinolysis.", blueprintCategory: "Hemostasis / Coagulation", subtopic: "D-dimer & FDP", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know D-dimer significance" },
  { stem: "The classic laboratory findings in DIC include:", options: ["Elevated fibrinogen, normal PT, normal aPTT", "Prolonged PT, prolonged aPTT, decreased fibrinogen, elevated D-dimer, decreased platelets", "Prolonged PT only with normal aPTT", "Normal PT, prolonged aPTT, normal platelets"], correctAnswer: 1, rationaleLong: "DIC is characterized by simultaneous widespread coagulation and fibrinolysis. Lab findings include: prolonged PT and aPTT (consumption of clotting factors), decreased fibrinogen (consumed), elevated D-dimer and FDPs (fibrinolysis), decreased platelets (consumed), and schistocytes on peripheral smear.", blueprintCategory: "Hemostasis / Coagulation", subtopic: "DIC", difficulty: 3, cognitiveLevel: "application", learningObjective: "Identify laboratory findings in DIC" },
  { stem: "A mixing study corrects the aPTT to normal. This indicates:", options: ["Presence of an inhibitor (e.g., lupus anticoagulant)", "Factor deficiency", "Heparin contamination", "DIC"], correctAnswer: 1, rationaleLong: "A mixing study involves mixing patient plasma 1:1 with normal pooled plasma and repeating the aPTT. If the aPTT corrects (normalizes), the prolongation is due to a factor deficiency (the normal plasma provides the missing factor). If it does not correct, an inhibitor (such as lupus anticoagulant or a specific factor inhibitor) is present.", blueprintCategory: "Hemostasis / Coagulation", subtopic: "Mixing Studies", difficulty: 3, cognitiveLevel: "application", learningObjective: "Interpret mixing study results" },
  { stem: "Which anticoagulant is monitored by the aPTT?", options: ["Warfarin", "Unfractionated heparin", "Aspirin", "Rivaroxaban"], correctAnswer: 1, rationaleLong: "Unfractionated heparin (UFH) is monitored by the aPTT. Heparin enhances antithrombin III activity, which inhibits thrombin and Factor Xa. The therapeutic aPTT range is typically 1.5-2.5 times the normal control value. Warfarin is monitored by PT/INR. LMWH is monitored by anti-Xa levels.", blueprintCategory: "Hemostasis / Coagulation", subtopic: "Anticoagulant Therapy Monitoring", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know anticoagulant monitoring tests" },
  { stem: "Hemophilia A is caused by deficiency of:", options: ["Factor VIII", "Factor IX", "Factor XI", "Von Willebrand factor"], correctAnswer: 0, rationaleLong: "Hemophilia A is an X-linked recessive bleeding disorder caused by deficiency or dysfunction of Factor VIII. It primarily affects males and presents with prolonged aPTT, normal PT, and normal bleeding time. Severity depends on Factor VIII activity: severe (<1%), moderate (1-5%), mild (5-40%).", blueprintCategory: "Hemostasis / Coagulation", subtopic: "Coagulation Cascade (Intrinsic, Extrinsic, Common)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know hemophilia A factor deficiency" },
  { stem: "Which of the following specimens is required for coagulation testing?", options: ["Serum", "EDTA plasma", "3.2% sodium citrate plasma", "Heparinized plasma"], correctAnswer: 2, rationaleLong: "Coagulation testing (PT, aPTT, fibrinogen, D-dimer) requires 3.2% sodium citrate (blue-top tube) plasma collected in a 9:1 blood-to-anticoagulant ratio. Citrate chelates calcium, preventing coagulation. Calcium is added back during testing. The specimen must be processed within 4 hours (or 24 hours if kept at room temperature for PT/INR).", blueprintCategory: "Hemostasis / Coagulation", subtopic: "Coagulation Cascade (Intrinsic, Extrinsic, Common)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know specimen requirements for coagulation testing" },
  { stem: "Von Willebrand disease is characterized by:", options: ["Prolonged PT only", "Prolonged aPTT and prolonged bleeding time", "Elevated D-dimer", "Normal aPTT with low platelets"], correctAnswer: 1, rationaleLong: "Von Willebrand disease (VWD) is the most common inherited bleeding disorder. VWF has two functions: platelet adhesion (hence prolonged bleeding time/PFA-100) and carrying Factor VIII (hence prolonged aPTT). PT is normal. Type 1 VWD (quantitative deficiency) is the most common type (75-80% of cases).", blueprintCategory: "Hemostasis / Coagulation", subtopic: "Platelet Function Testing", difficulty: 2, cognitiveLevel: "application", learningObjective: "Know laboratory findings in VWD" },
  { stem: "A lupus anticoagulant causes:", options: ["Prolonged aPTT in vitro but increased thrombotic risk in vivo", "Shortened aPTT", "Prolonged PT only", "Prolonged bleeding time"], correctAnswer: 0, rationaleLong: "Lupus anticoagulant (LA) is an antiphospholipid antibody that prolongs phospholipid-dependent coagulation tests (aPTT, dRVVT) in vitro but paradoxically increases thrombotic risk in vivo (not bleeding risk). LA does not correct with mixing studies. It is associated with antiphospholipid syndrome, recurrent thrombosis, and pregnancy loss.", blueprintCategory: "Hemostasis / Coagulation", subtopic: "Thrombophilia Screening", difficulty: 3, cognitiveLevel: "application", learningObjective: "Understand lupus anticoagulant" },
  { stem: "Which vitamin is essential for the synthesis of coagulation factors II, VII, IX, and X?", options: ["Vitamin A", "Vitamin C", "Vitamin D", "Vitamin K"], correctAnswer: 3, rationaleLong: "Vitamin K is required for the post-translational carboxylation of glutamic acid residues in Factors II (prothrombin), VII, IX, and X, as well as Proteins C and S. Warfarin inhibits vitamin K epoxide reductase, preventing vitamin K recycling and thus inhibiting the synthesis of functional vitamin K-dependent factors.", blueprintCategory: "Hemostasis / Coagulation", subtopic: "Coagulation Cascade (Intrinsic, Extrinsic, Common)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know vitamin K-dependent factors" },
  { stem: "The thrombin time is prolonged in all of the following EXCEPT:", options: ["Heparin therapy", "Hypofibrinogenemia", "Factor VII deficiency", "Elevated FDPs"], correctAnswer: 2, rationaleLong: "The thrombin time measures the conversion of fibrinogen to fibrin by adding thrombin directly to plasma. It is prolonged by heparin (inhibits thrombin), hypofibrinogenemia or dysfibrinogenemia, and elevated FDPs (which interfere with fibrin polymerization). Factor VII deficiency does not affect the thrombin time because thrombin is added directly.", blueprintCategory: "Hemostasis / Coagulation", subtopic: "Fibrinolysis", difficulty: 3, cognitiveLevel: "application", learningObjective: "Know conditions that prolong thrombin time" },
  { stem: "A patient on warfarin has an INR of 2.5. This is within the therapeutic range for:", options: ["Prophylaxis only", "Most standard indications (DVT, PE, atrial fibrillation)", "Mechanical heart valve replacement", "DIC treatment"], correctAnswer: 1, rationaleLong: "For most standard indications of warfarin therapy (DVT, PE, atrial fibrillation, stroke prevention), the therapeutic INR range is 2.0-3.0. For mechanical heart valve replacements, a higher target of 2.5-3.5 is often used. An INR of 2.5 falls within the standard therapeutic range.", blueprintCategory: "Hemostasis / Coagulation", subtopic: "Anticoagulant Therapy Monitoring", difficulty: 2, cognitiveLevel: "application", learningObjective: "Know therapeutic INR ranges" },
  { stem: "Fibrin degradation products (FDPs) are formed by:", options: ["Platelet aggregation", "Plasmin degradation of fibrin and fibrinogen", "Thrombin activation of fibrinogen", "Factor XIII cross-linking"], correctAnswer: 1, rationaleLong: "FDPs are produced when plasmin (the active fibrinolytic enzyme) degrades both fibrin clots and fibrinogen. FDP fragments (X, Y, D, E) interfere with fibrin polymerization, platelet function, and thrombin activity. Elevated FDPs are seen in DIC, fibrinolysis, liver disease, and thrombolytic therapy.", blueprintCategory: "Hemostasis / Coagulation", subtopic: "D-dimer & FDP", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Understand fibrinolysis products" },
  { stem: "Factor XIII deficiency is unique because:", options: ["It causes the most severe bleeding", "PT and aPTT are both normal despite clinical bleeding", "It only affects females", "It causes thrombosis rather than bleeding"], correctAnswer: 1, rationaleLong: "Factor XIII (fibrin-stabilizing factor) cross-links fibrin polymers, making the clot stable and resistant to fibrinolysis. Factor XIII deficiency causes delayed bleeding (often 24-48 hours post-surgery) despite normal PT and aPTT, because these tests do not assess cross-linking. The clot solubility test (5M urea) is used for diagnosis.", blueprintCategory: "Hemostasis / Coagulation", subtopic: "Coagulation Cascade (Intrinsic, Extrinsic, Common)", difficulty: 4, cognitiveLevel: "application", learningObjective: "Know Factor XIII deficiency characteristics" },
];

const microbiologyQuestions: MltQuestion[] = [
  { stem: "Which organism is catalase-positive and coagulase-positive?", options: ["Staphylococcus epidermidis", "Staphylococcus aureus", "Streptococcus pyogenes", "Enterococcus faecalis"], correctAnswer: 1, rationaleLong: "Staphylococcus aureus is both catalase-positive (distinguishing it from streptococci) and coagulase-positive (distinguishing it from other staphylococci). Coagulase production is the primary test for identifying S. aureus. CoNS (coagulase-negative staphylococci) such as S. epidermidis are catalase-positive but coagulase-negative.", blueprintCategory: "Microbiology", subtopic: "Gram-Positive Cocci", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Identify S. aureus by biochemical reactions" },
  { stem: "Group A Streptococcus (Streptococcus pyogenes) is:", options: ["Alpha-hemolytic", "Beta-hemolytic", "Gamma-hemolytic (non-hemolytic)", "Variable hemolysis"], correctAnswer: 1, rationaleLong: "Streptococcus pyogenes (GAS) produces beta-hemolysis (complete clearing of RBCs) on blood agar. It is identified by bacitracin sensitivity (zone of inhibition around bacitracin disk) and positive PYR test. S. pyogenes causes pharyngitis, impetigo, necrotizing fasciitis, and can lead to rheumatic fever and glomerulonephritis.", blueprintCategory: "Microbiology", subtopic: "Gram-Positive Cocci", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know hemolytic patterns of streptococci" },
  { stem: "A urine culture grows >100,000 CFU/mL of a lactose-fermenting, indole-positive, gram-negative rod. The most likely organism is:", options: ["Proteus mirabilis", "Escherichia coli", "Klebsiella pneumoniae", "Pseudomonas aeruginosa"], correctAnswer: 1, rationaleLong: "E. coli is the most common cause of urinary tract infections. It is a gram-negative rod that ferments lactose (pink colonies on MacConkey agar), is indole-positive, and is methyl red-positive. The IMViC pattern for E. coli is ++-- (indole+, MR+, VP-, citrate-). K. pneumoniae is indole-negative.", blueprintCategory: "Microbiology", subtopic: "Gram-Negative Rods (Enterobacteriaceae)", difficulty: 2, cognitiveLevel: "application", learningObjective: "Identify E. coli from biochemical reactions" },
  { stem: "Which organism produces a green pigment (pyocyanin) and has a fruity (grape-like) odor?", options: ["Escherichia coli", "Pseudomonas aeruginosa", "Proteus vulgaris", "Klebsiella pneumoniae"], correctAnswer: 1, rationaleLong: "Pseudomonas aeruginosa is a non-fermenting gram-negative rod that produces pyocyanin (blue-green pigment) and fluorescein (yellow-green pigment). It has a characteristic grape-like (fruity) odor. P. aeruginosa is oxidase-positive, grows at 42°C, and is an important cause of hospital-acquired infections, especially in immunocompromised patients.", blueprintCategory: "Microbiology", subtopic: "Gram-Negative Non-Fermenters", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Identify Pseudomonas aeruginosa" },
  { stem: "Which selective medium is used to isolate Salmonella and Shigella from stool cultures?", options: ["Blood agar", "MacConkey agar", "Hektoen enteric (HE) agar", "Chocolate agar"], correctAnswer: 2, rationaleLong: "Hektoen enteric (HE) agar is a selective and differential medium for isolating Salmonella and Shigella from stool specimens. Salmonella produces blue-green colonies with black centers (H2S production). Shigella produces green, transparent colonies (no H2S). Other selective media include XLD agar and SS agar.", blueprintCategory: "Microbiology", subtopic: "Gram-Negative Rods (Enterobacteriaceae)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know selective media for enteric pathogens" },
  { stem: "The CAMP test is used to identify:", options: ["Staphylococcus aureus", "Streptococcus agalactiae (Group B Strep)", "Streptococcus pyogenes (Group A Strep)", "Enterococcus faecalis"], correctAnswer: 1, rationaleLong: "The CAMP test identifies Group B Streptococcus (S. agalactiae). GBS produces CAMP factor, which enhances the hemolysis of S. aureus beta-lysin on sheep blood agar, creating an arrowhead-shaped zone of enhanced hemolysis. GBS is the most common cause of neonatal meningitis and sepsis.", blueprintCategory: "Microbiology", subtopic: "Gram-Positive Cocci", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know the CAMP test" },
  { stem: "An acid-fast bacillus (AFB) smear is positive. Which organism is most likely?", options: ["Staphylococcus aureus", "Mycobacterium tuberculosis", "Streptococcus pneumoniae", "Neisseria meningitidis"], correctAnswer: 1, rationaleLong: "Acid-fast bacilli have cell walls with high mycolic acid content that resist decolorization with acid-alcohol after being stained with carbol fuchsin (Ziehl-Neelsen or Kinyoun stain). Mycobacterium tuberculosis is the most common acid-fast organism encountered. M. tuberculosis appears as thin, beaded, rod-shaped organisms. AFB smear positivity suggests active TB.", blueprintCategory: "Microbiology", subtopic: "Mycobacteria (AFB)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know acid-fast organisms" },
  { stem: "Chocolate agar is required for the growth of which organism?", options: ["Escherichia coli", "Staphylococcus aureus", "Haemophilus influenzae", "Pseudomonas aeruginosa"], correctAnswer: 2, rationaleLong: "Haemophilus influenzae requires both X factor (hemin) and V factor (NAD) for growth. Chocolate agar (heated blood agar) provides both factors by lysing RBCs. H. influenzae does not grow on regular blood agar because V factor is inside intact RBCs. Satellitism around S. aureus colonies on blood agar can also demonstrate X and V factor requirements.", blueprintCategory: "Microbiology", subtopic: "Gram-Negative Rods (Enterobacteriaceae)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know growth requirements for Haemophilus" },
  { stem: "The optochin test is used to differentiate:", options: ["S. aureus from S. epidermidis", "S. pneumoniae from other alpha-hemolytic streptococci", "Group A from Group B streptococci", "E. coli from Klebsiella"], correctAnswer: 1, rationaleLong: "The optochin (ethylhydrocupreine) sensitivity test differentiates Streptococcus pneumoniae (optochin-sensitive, zone ≥14 mm with a 6 mm disk) from other alpha-hemolytic streptococci (optochin-resistant). Bile solubility is a confirmatory test for S. pneumoniae (positive = colonies dissolve in bile/sodium deoxycholate).", blueprintCategory: "Microbiology", subtopic: "Gram-Positive Cocci", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know optochin test purpose" },
  { stem: "Which organism swarms on blood agar and produces a strong urease reaction?", options: ["E. coli", "Proteus mirabilis", "Klebsiella pneumoniae", "Salmonella enteritidis"], correctAnswer: 1, rationaleLong: "Proteus mirabilis is a gram-negative rod known for its swarming motility on blood agar (waves of spreading growth) and strong urease activity. It is a common cause of UTIs, especially in patients with urinary catheters or structural abnormalities. Proteus infections are associated with struvite (staghorn) kidney stones.", blueprintCategory: "Microbiology", subtopic: "Gram-Negative Rods (Enterobacteriaceae)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Identify Proteus mirabilis characteristics" },
  { stem: "What is the purpose of the oxidase test?", options: ["Detect catalase production", "Detect cytochrome c oxidase", "Determine hemolysis pattern", "Measure antibiotic susceptibility"], correctAnswer: 1, rationaleLong: "The oxidase test detects the presence of cytochrome c oxidase, an enzyme in the electron transport chain. Oxidase-positive organisms include Neisseria, Pseudomonas, Aeromonas, Vibrio, and Campylobacter. Most Enterobacteriaceae are oxidase-negative. The reagent (tetramethyl-p-phenylenediamine) turns purple/blue when oxidized.", blueprintCategory: "Microbiology", subtopic: "Biochemical Identification", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know the oxidase test" },
  { stem: "Which medium is used for throat culture to detect Group A Streptococcus?", options: ["MacConkey agar", "5% sheep blood agar", "Thayer-Martin agar", "Sabouraud dextrose agar"], correctAnswer: 1, rationaleLong: "5% sheep blood agar (SBA) is the standard medium for throat cultures to detect Group A Streptococcus. SBA allows visualization of beta-hemolysis. Selective media containing trimethoprim-sulfamethoxazole may be used to inhibit normal flora and enhance GAS recovery.", blueprintCategory: "Microbiology", subtopic: "Culture & Sensitivity (C&S)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know culture media for throat specimens" },
  { stem: "Thayer-Martin agar is selective for:", options: ["Mycobacterium tuberculosis", "Neisseria gonorrhoeae and N. meningitidis", "Group A Streptococcus", "Bordetella pertussis"], correctAnswer: 1, rationaleLong: "Thayer-Martin agar (modified Thayer-Martin, MTM) is a selective chocolate agar containing antibiotics (vancomycin, colistin, nystatin, trimethoprim) that inhibit normal flora while allowing Neisseria gonorrhoeae and N. meningitidis to grow. It is used for specimens from sites with normal flora (genital, rectal, throat).", blueprintCategory: "Microbiology", subtopic: "Culture & Sensitivity (C&S)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know selective media for Neisseria" },
  { stem: "A Gram stain of CSF shows gram-negative diplococci. The most likely organism is:", options: ["Streptococcus pneumoniae", "Neisseria meningitidis", "Haemophilus influenzae", "Escherichia coli"], correctAnswer: 1, rationaleLong: "Gram-negative diplococci (kidney-bean shaped pairs) in CSF is highly suggestive of Neisseria meningitidis, a leading cause of bacterial meningitis in adolescents and young adults. S. pneumoniae appears as gram-positive lancet-shaped diplococci. H. influenzae appears as small gram-negative coccobacilli.", blueprintCategory: "Microbiology", subtopic: "Gram-Positive Cocci", difficulty: 2, cognitiveLevel: "application", learningObjective: "Correlate Gram stain morphology with organisms" },
  { stem: "The Kirby-Bauer method measures:", options: ["Minimum inhibitory concentration (MIC)", "Zone of inhibition around antibiotic disks", "Bacterial growth curves", "Biofilm formation"], correctAnswer: 1, rationaleLong: "The Kirby-Bauer disk diffusion method measures zones of inhibition around antibiotic disks on Mueller-Hinton agar. Zone diameters are measured and compared to CLSI standards to classify organisms as susceptible (S), intermediate (I), or resistant (R). This method is standardized for non-fastidious organisms.", blueprintCategory: "Microbiology", subtopic: "Antimicrobial Susceptibility Testing (AST)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know the Kirby-Bauer method" },
  { stem: "Mueller-Hinton agar is used for antibiotic susceptibility testing because:", options: ["It is enriched with blood", "It has standardized low calcium and magnesium content", "It is selective for gram-positive organisms", "It contains antibiotic indicators"], correctAnswer: 1, rationaleLong: "Mueller-Hinton agar is the standard medium for disk diffusion testing because it has a consistent and reproducible formulation, allows satisfactory growth of most non-fastidious organisms, has a standardized cation (Ca2+ and Mg2+) content that affects aminoglycoside and tetracycline results, and shows minimal interference with antibiotics.", blueprintCategory: "Microbiology", subtopic: "Antimicrobial Susceptibility Testing (AST)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know why Mueller-Hinton agar is used" },
  { stem: "Which organism is the most common cause of food poisoning with a rapid onset (1-6 hours)?", options: ["Salmonella enteritidis", "Staphylococcus aureus", "Clostridium perfringens", "E. coli O157:H7"], correctAnswer: 1, rationaleLong: "S. aureus produces heat-stable enterotoxins in food that cause rapid-onset food poisoning (1-6 hours). Symptoms include severe nausea, vomiting, and diarrhea. The toxin (not the organism) causes illness, so the food does not need to contain viable bacteria. Recovery is typically within 24-48 hours.", blueprintCategory: "Microbiology", subtopic: "Gram-Positive Cocci", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know causes of food poisoning by onset time" },
  { stem: "Clostridium difficile is identified by:", options: ["Catalase test", "Toxin detection (GDH screening and toxin A/B confirmation)", "CAMP test", "Oxidase test"], correctAnswer: 1, rationaleLong: "C. difficile diagnosis typically involves a two-step algorithm: screening with GDH (glutamate dehydrogenase) antigen detection, followed by confirmation with toxin A/B detection (EIA or NAAT/PCR). C. difficile produces toxin A (enterotoxin) and toxin B (cytotoxin), which cause antibiotic-associated diarrhea and pseudomembranous colitis.", blueprintCategory: "Microbiology", subtopic: "Anaerobes", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know C. difficile diagnostic approach" },
  { stem: "A blood culture grows a gram-positive coccus in clusters that is catalase-positive and coagulase-negative. Which organism is most likely?", options: ["Staphylococcus aureus", "Streptococcus pneumoniae", "Staphylococcus epidermidis", "Enterococcus faecalis"], correctAnswer: 2, rationaleLong: "Gram-positive cocci in clusters that are catalase-positive and coagulase-negative are classified as coagulase-negative staphylococci (CoNS). S. epidermidis is the most common CoNS. In blood cultures, it is often a contaminant but can be a true pathogen in patients with prosthetic devices, central lines, or immunosuppression.", blueprintCategory: "Microbiology", subtopic: "Gram-Positive Cocci", difficulty: 2, cognitiveLevel: "application", learningObjective: "Identify CoNS from clinical specimens" },
  { stem: "Which organism causes 'rice-water stools'?", options: ["Salmonella typhi", "Vibrio cholerae", "Shigella sonnei", "Campylobacter jejuni"], correctAnswer: 1, rationaleLong: "Vibrio cholerae causes cholera, characterized by profuse watery diarrhea ('rice-water stools') that can lead to severe dehydration and death if untreated. V. cholerae is a curved gram-negative rod that is oxidase-positive and grows on TCBS agar (thiosulfate citrate bile salts sucrose agar) as yellow colonies.", blueprintCategory: "Microbiology", subtopic: "Gram-Negative Rods (Enterobacteriaceae)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know clinical presentations of enteric pathogens" },
  { stem: "India ink stain of CSF is used to detect:", options: ["Mycobacterium tuberculosis", "Cryptococcus neoformans", "Neisseria meningitidis", "Treponema pallidum"], correctAnswer: 1, rationaleLong: "India ink (negative staining) is used to visualize the capsule of Cryptococcus neoformans in CSF. The yeast cells appear as bright bodies surrounded by a clear halo (capsule) against the dark ink background. Cryptococcal antigen (CrAg) testing by latex agglutination or lateral flow assay is more sensitive than India ink.", blueprintCategory: "Microbiology", subtopic: "Staining Techniques (Gram, AFB, India Ink)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know India ink stain purpose" },
  { stem: "The Gram stain procedure involves which sequence of reagents?", options: ["Crystal violet, Gram's iodine, alcohol-acetone decolorizer, safranin", "Safranin, crystal violet, iodine, decolorizer", "Crystal violet, decolorizer, iodine, safranin", "Methylene blue, Gram's iodine, decolorizer, crystal violet"], correctAnswer: 0, rationaleLong: "The Gram stain procedure: 1) Crystal violet (primary stain, 1 min), 2) Gram's iodine (mordant, 1 min), 3) Alcohol-acetone decolorizer (differentiation step), 4) Safranin (counterstain, 30 sec-1 min). Gram-positive organisms retain the crystal violet-iodine complex and appear purple. Gram-negative organisms lose the primary stain and take up safranin (pink).", blueprintCategory: "Microbiology", subtopic: "Staining Techniques (Gram, AFB, India Ink)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know Gram stain procedure" },
  { stem: "MRSA (methicillin-resistant S. aureus) resistance is mediated by:", options: ["Beta-lactamase production", "Altered PBP2a (mecA gene)", "Efflux pumps", "Porin mutations"], correctAnswer: 1, rationaleLong: "MRSA resistance is mediated by the mecA gene, which encodes an altered penicillin-binding protein (PBP2a/PBP2') with low affinity for beta-lactam antibiotics. This provides resistance to all beta-lactams (penicillins, cephalosporins, carbapenems). Detection uses cefoxitin disk screening or PCR for mecA/mecC genes.", blueprintCategory: "Microbiology", subtopic: "Antimicrobial Susceptibility Testing (AST)", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know MRSA resistance mechanism" },
  { stem: "Campylobacter jejuni grows best at which temperature?", options: ["25°C", "35°C", "42°C", "56°C"], correctAnswer: 2, rationaleLong: "Campylobacter jejuni is thermophilic and grows optimally at 42°C in a microaerophilic atmosphere (5% O2, 10% CO2). It requires selective media (Campy-BAP or CCDA) and incubation for 48-72 hours. C. jejuni is the most common bacterial cause of gastroenteritis worldwide and is associated with undercooked poultry.", blueprintCategory: "Microbiology", subtopic: "Gram-Negative Rods (Enterobacteriaceae)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know Campylobacter growth requirements" },
  { stem: "Which organism is associated with 'currant jelly' sputum?", options: ["Streptococcus pneumoniae", "Haemophilus influenzae", "Klebsiella pneumoniae", "Legionella pneumophila"], correctAnswer: 2, rationaleLong: "Klebsiella pneumoniae is associated with 'currant jelly' sputum (thick, bloody, mucoid sputum) in patients with necrotizing pneumonia, particularly alcoholics, diabetics, and hospitalized patients. K. pneumoniae produces a large mucoid capsule (mucoid colonies on agar), is urease-positive, and is a lactose fermenter.", blueprintCategory: "Microbiology", subtopic: "Gram-Negative Rods (Enterobacteriaceae)", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know clinical presentations of respiratory pathogens" },
  { stem: "Which quality control organism is used for testing antimicrobial susceptibility of gram-negative rods?", options: ["S. aureus ATCC 25923", "E. coli ATCC 25922", "S. pneumoniae ATCC 49619", "P. aeruginosa ATCC 27853"], correctAnswer: 1, rationaleLong: "E. coli ATCC 25922 is the standard QC organism for antimicrobial susceptibility testing of Enterobacteriaceae. P. aeruginosa ATCC 27853 is used for non-fermenter susceptibility testing. S. aureus ATCC 25923 is used for gram-positive organisms. QC must be performed at least weekly (daily if problems exist).", blueprintCategory: "Microbiology", subtopic: "Antimicrobial Susceptibility Testing (AST)", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know QC organisms for AST" },
  { stem: "A wound culture grows a beta-hemolytic gram-negative rod that is oxidase-positive and grows on MacConkey agar. The most likely organism is:", options: ["Pseudomonas aeruginosa", "Aeromonas hydrophila", "E. coli", "Proteus mirabilis"], correctAnswer: 1, rationaleLong: "Aeromonas hydrophila is a beta-hemolytic, oxidase-positive, gram-negative rod that grows on MacConkey agar (lactose variable). It is associated with wound infections (especially from fresh water exposure), gastroenteritis, and septicemia in immunocompromised patients. Oxidase positivity distinguishes it from Enterobacteriaceae.", blueprintCategory: "Microbiology", subtopic: "Gram-Negative Rods (Enterobacteriaceae)", difficulty: 4, cognitiveLevel: "application", learningObjective: "Identify Aeromonas from clinical specimens" },
  { stem: "ESBL (extended-spectrum beta-lactamase) producing organisms are resistant to:", options: ["Only penicillin", "Penicillins, cephalosporins, and aztreonam", "All antibiotics", "Carbapenems"], correctAnswer: 1, rationaleLong: "ESBL-producing organisms (most commonly E. coli and Klebsiella) are resistant to penicillins, extended-spectrum cephalosporins (3rd and 4th generation), and aztreonam. They remain susceptible to carbapenems (imipenem, meropenem), which are the treatment of choice. ESBLs are inhibited by clavulanate (used for detection).", blueprintCategory: "Microbiology", subtopic: "Antimicrobial Susceptibility Testing (AST)", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know ESBL resistance patterns" },
  { stem: "Which organism is comma-shaped (curved gram-negative rod), oxidase-positive, and grows on TCBS agar?", options: ["Helicobacter pylori", "Campylobacter jejuni", "Vibrio cholerae", "Aeromonas hydrophila"], correctAnswer: 2, rationaleLong: "Vibrio cholerae is a curved (comma-shaped) gram-negative rod that is oxidase-positive, grows on TCBS agar (as yellow sucrose-fermenting colonies), and requires sodium chloride for growth. V. cholerae produces cholera toxin, which causes massive secretory diarrhea. String test (0.5% sodium deoxycholate) is positive.", blueprintCategory: "Microbiology", subtopic: "Gram-Negative Rods (Enterobacteriaceae)", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Identify Vibrio cholerae" },
  { stem: "Which staining technique is used to identify Mycobacterium species?", options: ["Gram stain", "Ziehl-Neelsen (acid-fast) stain", "India ink", "Giemsa stain"], correctAnswer: 1, rationaleLong: "The Ziehl-Neelsen (ZN) stain is the classic acid-fast stain used to identify Mycobacterium species. Carbol fuchsin penetrates the mycolic acid-rich cell wall when heated (ZN) or with a higher concentration of phenol (Kinyoun cold method). Acid-fast organisms appear bright red against a blue background (methylene blue counterstain).", blueprintCategory: "Microbiology", subtopic: "Staining Techniques (Gram, AFB, India Ink)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know AFB staining techniques" },
  { stem: "A beta-hemolytic streptococcus is resistant to bacitracin and positive for the CAMP test. What is the identification?", options: ["Group A Streptococcus", "Group B Streptococcus (S. agalactiae)", "Group D Streptococcus", "Viridans streptococci"], correctAnswer: 1, rationaleLong: "Group B Streptococcus (S. agalactiae) is beta-hemolytic, resistant to bacitracin (Group A is sensitive), and positive for the CAMP test. It is also hippurate hydrolysis positive. GBS is the leading cause of neonatal sepsis and meningitis. Pregnant women are screened at 36-37 weeks for GBS colonization.", blueprintCategory: "Microbiology", subtopic: "Gram-Positive Cocci", difficulty: 2, cognitiveLevel: "application", learningObjective: "Differentiate GAS from GBS" },
  { stem: "The 'O' and 'H' antigens in Salmonella typing refer to:", options: ["Capsule and flagella", "Cell wall (somatic) and flagellar antigens", "Plasmid and chromosomal markers", "Toxin A and toxin B"], correctAnswer: 1, rationaleLong: "In Salmonella serotyping (Kauffman-White scheme), 'O' antigens are somatic (cell wall lipopolysaccharide) antigens that are heat-stable, and 'H' antigens are flagellar antigens that are heat-labile. The 'Vi' (virulence) antigen is a capsular antigen found in S. typhi. Serotyping is important for epidemiological surveillance.", blueprintCategory: "Microbiology", subtopic: "Biochemical Identification", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know Salmonella antigen types" },
  { stem: "Which of the following is the most common cause of community-acquired pneumonia?", options: ["Haemophilus influenzae", "Staphylococcus aureus", "Streptococcus pneumoniae", "Klebsiella pneumoniae"], correctAnswer: 2, rationaleLong: "Streptococcus pneumoniae (pneumococcus) is the most common cause of community-acquired bacterial pneumonia, as well as otitis media, sinusitis, and bacterial meningitis in adults. It appears as gram-positive lancet-shaped diplococci, is alpha-hemolytic, optochin-sensitive, and bile-soluble.", blueprintCategory: "Microbiology", subtopic: "Gram-Positive Cocci", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know common pathogens by site of infection" },
  { stem: "An E. coli isolate shows a zone of inhibition of 20 mm around ceftriaxone. According to CLSI, the breakpoint for susceptible is ≥23 mm. The isolate should be reported as:", options: ["Susceptible", "Intermediate", "Resistant", "Need to repeat testing"], correctAnswer: 1, rationaleLong: "For disk diffusion susceptibility testing, CLSI provides specific breakpoints for each antibiotic-organism combination. If the zone of inhibition is less than the susceptible breakpoint but not below the resistant breakpoint, it is classified as intermediate. A zone of 20 mm when the S breakpoint is ≥23 mm would fall in the intermediate or resistant category depending on the R breakpoint.", blueprintCategory: "Microbiology", subtopic: "Antimicrobial Susceptibility Testing (AST)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Interpret antibiotic susceptibility results" },
  { stem: "Which organism is the leading cause of hospital-acquired infections (HAIs) in the United States?", options: ["Staphylococcus aureus", "Clostridioides difficile", "Pseudomonas aeruginosa", "Escherichia coli"], correctAnswer: 1, rationaleLong: "Clostridioides difficile (formerly Clostridium difficile) is the most common cause of healthcare-associated infections in US hospitals. C. difficile infection (CDI) is associated with antibiotic use, particularly fluoroquinolones, clindamycin, and broad-spectrum cephalosporins. Prevention includes antibiotic stewardship and contact precautions.", blueprintCategory: "Microbiology", subtopic: "Infection Control & Surveillance", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know leading HAI pathogens" },
  { stem: "A KOH preparation of skin scrapings shows septate hyphae. This finding is most consistent with:", options: ["Candida species", "Dermatophyte infection", "Cryptococcus neoformans", "Aspergillus fumigatus"], correctAnswer: 1, rationaleLong: "KOH (potassium hydroxide) dissolves keratin and cellular debris, making fungal elements visible. Septate hyphae with dichotomous branching in skin scrapings are characteristic of dermatophyte infections (Trichophyton, Microsporum, Epidermophyton). Candida shows budding yeast and pseudohyphae. Cryptococcus is encapsulated yeast.", blueprintCategory: "Microbiology", subtopic: "Staining Techniques (Gram, AFB, India Ink)", difficulty: 2, cognitiveLevel: "application", learningObjective: "Interpret KOH preparations" },
  { stem: "Blood cultures should be drawn:", options: ["After antibiotic therapy is started", "Before antibiotic therapy is started, from two separate sites", "Only from central venous catheters", "From the IV line only"], correctAnswer: 1, rationaleLong: "Blood cultures should ideally be drawn before antibiotic therapy is initiated to maximize organism recovery. Two or more sets should be drawn from separate venipuncture sites to help distinguish true pathogens from contaminants. Each set consists of one aerobic and one anaerobic bottle. Proper skin antisepsis is critical.", blueprintCategory: "Microbiology", subtopic: "Culture & Sensitivity (C&S)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know blood culture collection guidelines" },
  { stem: "Legionella pneumophila is best cultured on which medium?", options: ["Blood agar", "MacConkey agar", "BCYE (buffered charcoal yeast extract) agar", "Chocolate agar"], correctAnswer: 2, rationaleLong: "Legionella pneumophila requires BCYE agar supplemented with L-cysteine (essential amino acid) and ferric pyrophosphate for growth. Legionella does not grow on standard laboratory media. Incubation requires 3-5 days at 35°C in a moist environment. Urine antigen detection is a rapid diagnostic method for L. pneumophila serogroup 1.", blueprintCategory: "Microbiology", subtopic: "Culture & Sensitivity (C&S)", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know Legionella culture requirements" },
  { stem: "MALDI-TOF mass spectrometry in microbiology is used for:", options: ["Antimicrobial susceptibility testing", "Rapid organism identification from colonies", "Blood culture monitoring", "Nucleic acid detection"], correctAnswer: 1, rationaleLong: "MALDI-TOF (matrix-assisted laser desorption/ionization-time of flight) mass spectrometry is used for rapid identification of microorganisms from isolated colonies. It generates a unique protein profile (spectrum) that is matched against a reference database. Results are available in minutes, compared to hours/days for conventional biochemical methods.", blueprintCategory: "Microbiology", subtopic: "Automated Microbiology Systems (MALDI-TOF)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know MALDI-TOF applications" },
  { stem: "Which organism causes whooping cough?", options: ["Corynebacterium diphtheriae", "Bordetella pertussis", "Haemophilus influenzae", "Moraxella catarrhalis"], correctAnswer: 1, rationaleLong: "Bordetella pertussis causes pertussis (whooping cough), characterized by paroxysmal coughing fits followed by an inspiratory 'whoop.' B. pertussis is a small gram-negative coccobacillus that requires Bordet-Gengou agar or Regan-Lowe agar for culture. PCR (nasopharyngeal swab) is the preferred diagnostic method.", blueprintCategory: "Microbiology", subtopic: "Gram-Negative Rods (Enterobacteriaceae)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know Bordetella pertussis" },
  { stem: "Listeria monocytogenes is unique among gram-positive rods because it:", options: ["Is acid-fast", "Demonstrates tumbling motility at 25°C", "Produces beta-hemolysis only at 42°C", "Requires chocolate agar"], correctAnswer: 1, rationaleLong: "Listeria monocytogenes is a gram-positive rod that demonstrates characteristic tumbling motility at 25°C (room temperature) but not at 37°C. It is beta-hemolytic, catalase-positive, and able to grow at refrigerator temperatures (4°C, 'cold enrichment'). Listeria causes meningitis and sepsis in neonates, elderly, and immunocompromised patients.", blueprintCategory: "Microbiology", subtopic: "Gram-Positive Cocci", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know Listeria characteristics" },
  { stem: "The bile esculin test is positive for which group of organisms?", options: ["Group A streptococci", "Staphylococci", "Enterococci and Group D streptococci", "Viridans streptococci"], correctAnswer: 2, rationaleLong: "The bile esculin test is used to identify enterococci and Group D streptococci (such as S. bovis). These organisms can grow in the presence of 40% bile and hydrolyze esculin, producing a dark brown/black color on the medium. This test, along with growth in 6.5% NaCl broth, helps differentiate enterococci from other streptococci.", blueprintCategory: "Microbiology", subtopic: "Biochemical Identification", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know bile esculin test results" },
  { stem: "Helicobacter pylori is associated with:", options: ["Pharyngitis", "Gastric ulcers and gastric cancer", "Urinary tract infections", "Pneumonia"], correctAnswer: 1, rationaleLong: "Helicobacter pylori is a spiral-shaped, gram-negative microaerophilic bacterium that colonizes the gastric mucosa. It is a major cause of chronic gastritis, peptic ulcers, and is classified as a Group 1 carcinogen (gastric cancer and MALT lymphoma). Diagnosis includes urea breath test, stool antigen test, or biopsy with rapid urease test.", blueprintCategory: "Microbiology", subtopic: "Gram-Negative Rods (Enterobacteriaceae)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know H. pylori associations" },
];

const bloodBankQuestions: MltQuestion[] = [
  { stem: "What is the correct order for forward and reverse typing in ABO blood grouping?", options: ["Forward typing uses known antisera against patient RBCs; reverse typing uses known RBCs against patient serum", "Forward uses patient serum; reverse uses known antisera", "Both use the same reagents", "Forward typing tests platelets; reverse tests serum"], correctAnswer: 0, rationaleLong: "In ABO grouping, forward (cell) typing tests patient RBCs with known anti-A and anti-B antisera to detect antigens on the cells. Reverse (serum/back) typing tests patient serum/plasma with known A1 and B reagent red cells to detect ABO antibodies. Both must agree for a valid ABO interpretation.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "ABO & Rh Blood Group Systems", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Understand ABO typing methodology" },
  { stem: "A patient types as A positive. Forward typing shows agglutination with anti-A only. Reverse typing shows agglutination with B cells only. What is the correct ABO/Rh type?", options: ["A positive", "B positive", "AB positive", "O positive"], correctAnswer: 0, rationaleLong: "Forward typing: anti-A positive, anti-B negative = A antigen present. Reverse typing: A1 cells negative, B cells positive = anti-B present. The forward and reverse agree: Blood type A. The patient is Rh positive. This is a concordant ABO result — Type A positive.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "ABO & Rh Blood Group Systems", difficulty: 2, cognitiveLevel: "application", learningObjective: "Interpret ABO typing results" },
  { stem: "What antibody is clinically significant and commonly associated with hemolytic disease of the fetus and newborn (HDFN)?", options: ["Anti-M", "Anti-D", "Anti-Lewis a", "Anti-P1"], correctAnswer: 1, rationaleLong: "Anti-D (Rh antibody) is the most clinically significant antibody associated with HDFN. It is an IgG antibody that crosses the placenta and causes destruction of fetal RBCs. RhIG (Rh immune globulin) is given to Rh-negative mothers to prevent anti-D formation. Anti-Lea and anti-P1 are IgM antibodies that do not cross the placenta.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Hemolytic Disease of the Fetus & Newborn (HDFN)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know antibodies causing HDFN" },
  { stem: "The direct antiglobulin test (DAT) detects:", options: ["Antibodies in patient serum", "Antibodies or complement bound to patient RBCs in vivo", "ABO antibodies", "Platelet antibodies"], correctAnswer: 1, rationaleLong: "The DAT detects IgG antibodies and/or complement (C3d) that have attached to patient red blood cells in vivo. It is used to diagnose autoimmune hemolytic anemia (AIHA), hemolytic transfusion reactions, and HDFN. Anti-human globulin (AHG/Coombs reagent) is added directly to washed patient RBCs.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Direct & Indirect Antiglobulin Test (DAT/IAT)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know DAT purpose and principle" },
  { stem: "The indirect antiglobulin test (IAT) is used for:", options: ["Detecting in vivo antibody coating on RBCs", "Detecting unexpected antibodies in patient serum (antibody screen)", "ABO forward typing", "Platelet crossmatching"], correctAnswer: 1, rationaleLong: "The IAT (indirect Coombs test) detects unexpected antibodies in patient serum/plasma. It involves incubating patient serum with known screening cells, washing, then adding AHG reagent. It is used for antibody screening, antibody identification, crossmatching (major), and prenatal testing. Any unexpected antibody that reacts at 37°C or AHG phase is clinically significant.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Direct & Indirect Antiglobulin Test (DAT/IAT)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know IAT purpose and applications" },
  { stem: "Which phase of crossmatching is the most important for detecting clinically significant antibodies?", options: ["Immediate spin phase", "Room temperature phase", "37°C and AHG (antiglobulin) phase", "Cold phase"], correctAnswer: 2, rationaleLong: "The 37°C/AHG phase is the most important phase of crossmatching because it detects clinically significant IgG antibodies (anti-D, anti-K, anti-Fya, anti-Jka, etc.) that cause hemolytic transfusion reactions. The immediate spin (IS) phase primarily detects ABO incompatibility. Cold-reactive antibodies detected at room temperature are usually clinically insignificant.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Crossmatch Procedures", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know crossmatch phases" },
  { stem: "A patient experiences fever, chills, and back pain within 15 minutes of starting a transfusion. The most likely cause is:", options: ["Febrile non-hemolytic transfusion reaction", "Acute hemolytic transfusion reaction", "Allergic transfusion reaction", "Bacterial contamination"], correctAnswer: 1, rationaleLong: "Acute hemolytic transfusion reactions (AHTR) typically present within minutes to hours of transfusion with fever, chills, back pain, hemoglobinuria, hypotension, and DIC. They are caused by ABO-incompatible transfusion (most commonly clerical error). Immediate action: stop the transfusion, maintain IV access, notify blood bank, send samples for investigation.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Transfusion Reactions", difficulty: 3, cognitiveLevel: "application", learningObjective: "Recognize acute hemolytic transfusion reaction" },
  { stem: "Which blood component is indicated for a patient with massive bleeding and fibrinogen <100 mg/dL?", options: ["Packed red blood cells", "Fresh frozen plasma (FFP)", "Cryoprecipitate", "Platelet concentrate"], correctAnswer: 2, rationaleLong: "Cryoprecipitate is the blood component richest in fibrinogen (also contains Factor VIII, Factor XIII, VWF, and fibronectin). It is indicated when fibrinogen levels are <100 mg/dL, particularly in DIC, massive transfusion, and fibrinogen deficiency. Each unit of cryo raises fibrinogen by approximately 5-10 mg/dL.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Component Therapy", difficulty: 3, cognitiveLevel: "application", learningObjective: "Know blood component indications" },
  { stem: "What is the storage temperature for platelet concentrates?", options: ["1-6°C", "20-24°C with continuous agitation", "-18°C or colder", "37°C"], correctAnswer: 1, rationaleLong: "Platelet concentrates must be stored at 20-24°C (room temperature) with continuous gentle agitation to prevent aggregation and maintain viability. Shelf life is 5 days. Platelets stored at colder temperatures lose their discoid shape and function. The risk of bacterial contamination increases with storage duration at room temperature.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Component Therapy", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know blood component storage requirements" },
  { stem: "What is the storage temperature and shelf life for packed red blood cells preserved in CPDA-1?", options: ["1-6°C for 21 days", "1-6°C for 35 days", "20-24°C for 5 days", "-18°C for 1 year"], correctAnswer: 1, rationaleLong: "Packed RBCs stored in CPDA-1 (citrate-phosphate-dextrose-adenine) are kept at 1-6°C for up to 35 days. Additive solutions (AS-1, AS-3, AS-5) extend storage to 42 days. Frozen RBCs (with glycerol) stored at -65°C or colder have a shelf life of 10 years.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Component Therapy", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know RBC storage conditions" },
  { stem: "In emergency situations when patient's blood type is unknown, which blood type RBCs should be issued?", options: ["A positive", "AB positive", "O negative", "B negative"], correctAnswer: 2, rationaleLong: "O-negative RBCs are the 'universal donor' for emergency transfusion when the patient's blood type is unknown. O-negative cells lack A, B, and D antigens, minimizing the risk of a major hemolytic reaction. For males and post-menopausal females, O-positive RBCs may be used to conserve the limited O-negative supply.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "ABO & Rh Blood Group Systems", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know emergency blood product selection" },
  { stem: "An antibody identification panel shows reactivity at IAT phase with all cells positive for the Kell (K) antigen and negative with all K-negative cells. The antibody is most likely:", options: ["Anti-E", "Anti-K", "Anti-Jka", "Anti-Fya"], correctAnswer: 1, rationaleLong: "When an antibody reacts exclusively with cells that possess the K (Kell) antigen and is non-reactive with K-negative cells, the pattern identifies anti-K. Anti-K is an IgG antibody that is clinically significant, causing hemolytic transfusion reactions and HDFN. K-negative units must be selected for transfusion.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Antibody Identification", difficulty: 3, cognitiveLevel: "application", learningObjective: "Interpret antibody identification panels" },
  { stem: "Which of the following is the universal plasma donor?", options: ["Type O", "Type A", "Type B", "Type AB"], correctAnswer: 3, rationaleLong: "Type AB plasma is the universal plasma donor because it contains neither anti-A nor anti-B antibodies. AB plasma can be safely transfused to patients of any ABO type without causing hemolysis of the recipient's RBCs. Conversely, type O is the universal RBC donor.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "ABO & Rh Blood Group Systems", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know universal donor/recipient types" },
  { stem: "What is the purpose of the antiglobulin (Coombs) reagent?", options: ["To detect ABO antibodies", "To cross-link IgG-coated RBCs, causing visible agglutination", "To lyse complement-coated cells", "To prevent rouleaux formation"], correctAnswer: 1, rationaleLong: "Anti-human globulin (AHG/Coombs reagent) contains antibodies against human IgG and/or complement (C3d). IgG antibodies are too small to directly agglutinate RBCs. AHG cross-links the IgG molecules on adjacent sensitized RBCs, producing visible agglutination. This is the basis of both the DAT and IAT.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Direct & Indirect Antiglobulin Test (DAT/IAT)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Understand AHG reagent function" },
  { stem: "Leukoreduction of blood products is performed to:", options: ["Prevent bacterial contamination", "Reduce febrile non-hemolytic transfusion reactions and CMV transmission", "Increase shelf life of products", "Remove platelets"], correctAnswer: 1, rationaleLong: "Leukoreduction (leukocyte reduction) removes >99.9% of WBCs from blood products. Benefits include: reduced febrile non-hemolytic transfusion reactions (caused by recipient antibodies against donor WBC antigens), reduced CMV transmission (CMV resides in WBCs), reduced HLA alloimmunization, and reduced risk of TRALI.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Irradiation & Leukoreduction", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know leukoreduction benefits" },
  { stem: "Irradiation of blood products is performed to prevent:", options: ["Bacterial contamination", "Transfusion-associated graft-versus-host disease (TA-GVHD)", "ABO incompatibility", "Febrile reactions"], correctAnswer: 1, rationaleLong: "Gamma irradiation (25 Gy) of cellular blood products inactivates donor T lymphocytes, preventing TA-GVHD. TA-GVHD occurs when immunocompetent donor T cells engraft in an immunocompromised recipient and attack host tissues. Indications include: directed donations from relatives, HLA-matched products, intrauterine transfusions, and severely immunosuppressed patients.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Irradiation & Leukoreduction", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know indications for irradiated blood products" },
  { stem: "A positive antibody screen is detected in a prenatal patient at 28 weeks gestation. The antibody is identified as anti-D. What intervention is indicated?", options: ["No intervention needed", "RhIG administration", "Intrauterine transfusion", "Anti-D monitoring only — RhIG is contraindicated"], correctAnswer: 3, rationaleLong: "If a prenatal patient already has anti-D (is already alloimmunized), RhIG is NOT indicated because it cannot prevent sensitization that has already occurred. Instead, the anti-D titer should be monitored throughout pregnancy. If titers reach critical levels, further evaluation (MCA Doppler, amniocentesis) and possible intrauterine transfusion may be needed.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Hemolytic Disease of the Fetus & Newborn (HDFN)", difficulty: 4, cognitiveLevel: "analysis", learningObjective: "Manage anti-D in pregnancy" },
  { stem: "What is the most common cause of a fatal hemolytic transfusion reaction?", options: ["Rh incompatibility", "ABO incompatibility due to clerical error", "Anti-Kell antibodies", "Cold agglutinins"], correctAnswer: 1, rationaleLong: "ABO incompatibility (most often due to clerical error — wrong patient identification or mislabeled specimen) is the most common cause of fatal hemolytic transfusion reactions. The intravascular hemolysis caused by ABO antibodies (IgM, complement-activating) can lead to DIC, renal failure, and death. Patient identification is the most critical step.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Transfusion Reactions", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know the leading cause of fatal transfusion reactions" },
  { stem: "Fresh frozen plasma (FFP) must be transfused within what time frame after thawing?", options: ["4 hours", "24 hours", "48 hours", "5 days"], correctAnswer: 1, rationaleLong: "FFP must be transfused within 24 hours of thawing when stored at 1-6°C (some institutions use shorter times). Thawed FFP can be relabeled as 'thawed plasma' and stored for up to 5 days, but it has reduced levels of labile factors (V and VIII). FFP is stored at -18°C or colder for up to 1 year.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Component Therapy", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know FFP transfusion requirements" },
  { stem: "An ABO discrepancy exists when:", options: ["Forward and reverse typing results agree", "Forward and reverse typing results do not agree", "The Rh type is unknown", "The crossmatch is compatible"], correctAnswer: 1, rationaleLong: "An ABO discrepancy exists when the forward (cell) typing results do not agree with the reverse (serum) typing results. Causes include: subgroups of A or B, cold autoantibodies, missing antibodies (immunodeficiency, newborns), extra antibodies (alloantibodies), and technical errors. Discrepancies must be resolved before issuing blood.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "ABO & Rh Blood Group Systems", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Recognize ABO discrepancies" },
  { stem: "Which immunoglobulin class are ABO antibodies (isoagglutinins)?", options: ["IgA", "IgG only", "IgM (predominantly), with some IgG", "IgE"], correctAnswer: 2, rationaleLong: "ABO antibodies (isoagglutinins) are naturally occurring antibodies that are predominantly IgM. They activate complement and cause intravascular hemolysis in ABO-incompatible transfusions. Some IgG anti-A and anti-B is also present, which can cross the placenta and cause ABO HDFN (usually mild). Group O individuals have more IgG ABO antibodies.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "ABO & Rh Blood Group Systems", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know ABO antibody immunoglobulin class" },
  { stem: "TRALI (transfusion-related acute lung injury) is caused by:", options: ["Volume overload", "Donor antibodies against recipient WBC antigens (HLA/HNA)", "Bacterial contamination", "ABO incompatibility"], correctAnswer: 1, rationaleLong: "TRALI is a serious transfusion complication caused primarily by donor antibodies (anti-HLA or anti-HNA) that activate recipient neutrophils in the pulmonary vasculature. This leads to non-cardiogenic pulmonary edema presenting as acute respiratory distress within 6 hours of transfusion. TRALI mitigation includes using male-only plasma donors.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Transfusion Reactions", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Understand TRALI pathophysiology" },
  { stem: "The Rh blood group system is clinically significant because:", options: ["Antibodies are always naturally occurring", "Anti-D can cause severe HDFN and hemolytic transfusion reactions", "Rh antigens are found only on platelets", "Rh antibodies are always IgM"], correctAnswer: 1, rationaleLong: "The Rh blood group system is clinically significant because anti-D (and other Rh antibodies like anti-c, anti-E) are IgG antibodies that cross the placenta, causing HDFN, and cause extravascular hemolytic transfusion reactions. Rh antibodies are immune (not naturally occurring) and develop after exposure to Rh-positive RBCs through transfusion or pregnancy.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "ABO & Rh Blood Group Systems", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know Rh system clinical significance" },
  { stem: "A patient with anti-Jka receives Jk(a-) compatible blood. Two weeks later, the antibody is no longer detectable. Upon repeat transfusion with Jk(a+) blood, a delayed hemolytic transfusion reaction occurs. This is an example of:", options: ["Primary immune response", "Anamnestic (secondary immune) response", "Autoimmune reaction", "Bacterial contamination"], correctAnswer: 1, rationaleLong: "This is a classic example of an anamnestic (secondary/memory) response. Anti-Jka is notorious for evanescence (falling below detectable levels). Upon re-exposure to Jk(a+) cells, memory B cells rapidly produce IgG anti-Jka, causing a delayed hemolytic transfusion reaction (typically 3-14 days post-transfusion). This underscores the importance of antibody history records.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Antibody Identification", difficulty: 4, cognitiveLevel: "analysis", learningObjective: "Understand anamnestic responses in transfusion" },
  { stem: "Which test is used to determine if fetal RBCs have entered the maternal circulation?", options: ["Direct antiglobulin test", "Kleihauer-Betke test (acid elution)", "Antibody identification panel", "Indirect antiglobulin test"], correctAnswer: 1, rationaleLong: "The Kleihauer-Betke (KB) test (acid elution test) detects fetal hemoglobin (HbF)-containing cells in the maternal circulation. Acid treatment elutes adult hemoglobin from maternal RBCs (ghost cells), while fetal cells retain HbF and stain pink. The percentage of fetal cells is used to calculate the dose of RhIG needed.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Hemolytic Disease of the Fetus & Newborn (HDFN)", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know the Kleihauer-Betke test" },
  { stem: "Blood donor screening includes all of the following EXCEPT:", options: ["Testing for HIV antibodies", "Testing for hepatitis B surface antigen", "ABO/Rh typing", "Complete blood count with differential"], correctAnswer: 3, rationaleLong: "Blood donor screening includes: ABO/Rh typing, antibody screen, infectious disease testing (HIV-1/2, HCV, HBV, syphilis, HTLV-I/II, WNV, Zika, Babesia, T. cruzi), and hemoglobin/hematocrit measurement. A complete CBC with differential is not required for donor screening. Donors must meet eligibility criteria for age, weight, vital signs, and health history.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Blood Donor Screening", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know blood donor screening requirements" },
  { stem: "Washed RBCs are indicated for patients with:", options: ["Iron deficiency anemia", "History of severe allergic/anaphylactic transfusion reactions", "Thrombocytopenia", "Sickle cell disease"], correctAnswer: 1, rationaleLong: "Washed RBCs (saline-washed to remove plasma proteins) are indicated for patients with severe allergic or anaphylactic transfusion reactions, particularly those with IgA deficiency who have anti-IgA antibodies. Washing removes plasma proteins, including IgA, that can trigger anaphylaxis. Washed units must be used within 24 hours.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Component Therapy", difficulty: 3, cognitiveLevel: "application", learningObjective: "Know indications for washed RBCs" },
  { stem: "Gel technology (column agglutination) in blood banking offers which advantage over traditional tube testing?", options: ["Lower cost", "Standardized, objective reading of results", "Faster room temperature testing", "No need for AHG reagent"], correctAnswer: 1, rationaleLong: "Gel column technology provides standardized, objective, and reproducible results because agglutinated cells are trapped in the gel matrix while unagglutinated cells pass through. It eliminates the subjectivity of tube testing interpretation, reduces the washing step, and results are stable for later review. It has become the standard in many blood banks.", blueprintCategory: "Immunohematology / Blood Banking", subtopic: "Crossmatch Procedures", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know advantages of gel technology" },
];

const urinalysisQuestions: MltQuestion[] = [
  { stem: "A urine specimen has a specific gravity of 1.035. This indicates:", options: ["Dilute urine", "Concentrated urine", "Normal specific gravity", "Isosthenuria"], correctAnswer: 1, rationaleLong: "Normal urine specific gravity ranges from 1.001 to 1.035. A specific gravity of 1.035 indicates concentrated urine. Concentrated urine is seen in dehydration, SIADH, and decreased fluid intake. A specific gravity consistently near 1.010 (isosthenuria) suggests inability to concentrate urine (renal tubular dysfunction).", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Physical Examination of Urine", difficulty: 1, cognitiveLevel: "application", learningObjective: "Interpret urine specific gravity" },
  { stem: "Which of the following is the most common crystal found in acidic urine?", options: ["Calcium oxalate", "Triple phosphate", "Amorphous phosphates", "Calcium carbonate"], correctAnswer: 0, rationaleLong: "Calcium oxalate crystals (dihydrate form appears as octahedral/envelope-shaped; monohydrate as oval/dumbbell) are the most common crystals found in acidic urine. Triple phosphate (struvite/coffin lid) and amorphous phosphates are found in alkaline urine. Calcium oxalate crystals can be normal but may be increased in ethylene glycol poisoning.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Microscopic Sediment Analysis", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Identify common urine crystals" },
  { stem: "The presence of RBC casts in urine sediment is indicative of:", options: ["Urinary tract infection", "Glomerulonephritis", "Cystitis", "Renal calculi"], correctAnswer: 1, rationaleLong: "RBC casts indicate bleeding at the glomerular or tubular level and are pathognomonic for glomerulonephritis. They form when RBCs are incorporated into the Tamm-Horsfall protein matrix in the renal tubules. RBC casts differentiate upper urinary tract (renal) bleeding from lower urinary tract bleeding.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Microscopic Sediment Analysis", difficulty: 2, cognitiveLevel: "application", learningObjective: "Interpret urinary casts" },
  { stem: "A urine dipstick shows positive blood but no RBCs are seen on microscopic examination. The most likely explanation is:", options: ["False-positive dipstick", "Hemoglobinuria or myoglobinuria", "Contaminated specimen", "Expired reagent strips"], correctAnswer: 1, rationaleLong: "The urine dipstick blood pad detects the peroxidase activity of hemoglobin, whether it is inside RBCs, free hemoglobin (hemoglobinuria), or myoglobin (myoglobinuria). A positive dipstick without microscopic RBCs suggests hemoglobinuria (from intravascular hemolysis) or myoglobinuria (from rhabdomyolysis). Ascorbic acid can cause false negatives.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Chemical Examination (Dipstick)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Troubleshoot discrepant dipstick and microscopy results" },
  { stem: "Waxy casts are most commonly associated with:", options: ["Acute pyelonephritis", "Chronic renal failure", "Normal finding", "Urinary tract infection"], correctAnswer: 1, rationaleLong: "Waxy casts are the final stage of cast degeneration, formed from degenerated granular casts that have remained in the nephron for an extended period (indicating severely reduced urine flow). They have smooth, homogeneous, waxy appearance with sharp, broken edges. They are associated with chronic renal failure, renal transplant rejection, and severe renal disease.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Microscopic Sediment Analysis", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know cast types and clinical significance" },
  { stem: "Which urine dipstick finding is most consistent with a urinary tract infection?", options: ["Positive glucose", "Positive nitrite and positive leukocyte esterase", "Positive bilirubin", "Positive ketones"], correctAnswer: 1, rationaleLong: "Positive nitrite (indicates bacteria that reduce nitrate to nitrite — most Enterobacteriaceae) and positive leukocyte esterase (indicates WBCs/neutrophils) together are highly suggestive of a UTI. Neither test alone is sufficient. Some organisms (Enterococcus, Staphylococcus) do not reduce nitrate, so a negative nitrite does not rule out UTI.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Chemical Examination (Dipstick)", difficulty: 2, cognitiveLevel: "application", learningObjective: "Interpret urine dipstick for UTI" },
  { stem: "The normal color of urine is due to:", options: ["Bilirubin", "Urochrome (urobilin)", "Hemoglobin", "Melanin"], correctAnswer: 1, rationaleLong: "The normal yellow color of urine is primarily due to urochrome (urobilin), a pigment produced from the breakdown of hemoglobin through bilirubin metabolism. The intensity of yellow color varies with concentration — dilute urine is pale yellow, concentrated urine is dark amber.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Physical Examination of Urine", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know the source of normal urine color" },
  { stem: "CSF with a WBC count of 500/μL, predominantly neutrophils, elevated protein, and decreased glucose is most consistent with:", options: ["Viral meningitis", "Bacterial meningitis", "Normal CSF", "Multiple sclerosis"], correctAnswer: 1, rationaleLong: "Bacterial meningitis typically shows: elevated WBC (100-10,000/μL, predominantly neutrophils), elevated protein (>100 mg/dL), and markedly decreased glucose (<40 mg/dL or CSF/blood glucose ratio <0.4). Viral meningitis shows lymphocytic predominance, mildly elevated protein, and normal glucose.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Cerebrospinal Fluid (CSF)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Differentiate bacterial from viral meningitis by CSF analysis" },
  { stem: "Normal CSF glucose is approximately what percentage of blood glucose?", options: ["10-20%", "40-60%", "60-70%", "80-100%"], correctAnswer: 2, rationaleLong: "Normal CSF glucose is approximately 60-70% of blood glucose (typically 40-70 mg/dL when blood glucose is normal). A CSF glucose significantly below 60% of blood glucose suggests bacterial meningitis, fungal meningitis, or malignancy. Viral meningitis usually has normal CSF glucose.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Cerebrospinal Fluid (CSF)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know normal CSF glucose ratio" },
  { stem: "Which type of cast is formed by degeneration of cellular casts?", options: ["Hyaline cast", "Granular cast", "Waxy cast", "Broad cast"], correctAnswer: 1, rationaleLong: "Granular casts are formed from the degeneration of cellular casts (WBC, RBC, or epithelial cell casts). As cells within the cast matrix break down, they form coarse granular casts, then fine granular casts, and eventually waxy casts. Granular casts indicate renal disease and are considered pathological.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Microscopic Sediment Analysis", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Understand cast formation and degeneration" },
  { stem: "Ketonuria is commonly found in:", options: ["Urinary tract infections", "Diabetic ketoacidosis and starvation", "Renal calculi", "Liver cirrhosis"], correctAnswer: 1, rationaleLong: "Ketone bodies (acetoacetate, beta-hydroxybutyrate, acetone) appear in urine when fat metabolism is increased due to inadequate carbohydrate utilization. This occurs in diabetic ketoacidosis (DKA), starvation, low-carbohydrate diets, vomiting, and febrile illness in children. The urine dipstick detects acetoacetate (nitroprusside reaction).", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Chemical Examination (Dipstick)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know causes of ketonuria" },
  { stem: "A synovial fluid specimen shows negatively birefringent, needle-shaped crystals under polarized microscopy. This is most consistent with:", options: ["Pseudogout (CPPD)", "Gout (monosodium urate)", "Septic arthritis", "Rheumatoid arthritis"], correctAnswer: 1, rationaleLong: "Negatively birefringent, needle-shaped crystals are monosodium urate (MSU) crystals, diagnostic of gout. Under compensated polarized microscopy, MSU crystals appear yellow when parallel to the slow ray of the compensator. Calcium pyrophosphate dihydrate (CPPD) crystals in pseudogout are weakly positively birefringent and rhomboid-shaped.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Synovial Fluid", difficulty: 3, cognitiveLevel: "application", learningObjective: "Identify synovial fluid crystals" },
  { stem: "A pleural fluid with a protein ratio (fluid/serum) >0.5 and LDH ratio (fluid/serum) >0.6 is classified as:", options: ["Transudate", "Exudate", "Chylous effusion", "Normal"], correctAnswer: 1, rationaleLong: "Light's criteria classify pleural fluid as an exudate if ANY of the following are met: fluid/serum protein ratio >0.5, fluid/serum LDH ratio >0.6, or fluid LDH >2/3 the upper limit of normal serum LDH. Exudates indicate an inflammatory process (infection, malignancy, PE). Transudates are caused by systemic factors (CHF, cirrhosis).", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Serous Fluids (Pleural, Peritoneal, Pericardial)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Apply Light's criteria" },
  { stem: "WBC casts in urine indicate:", options: ["Lower urinary tract infection", "Pyelonephritis or interstitial nephritis", "Glomerulonephritis", "Normal finding"], correctAnswer: 1, rationaleLong: "WBC casts indicate inflammation within the renal tubules, most commonly seen in pyelonephritis (upper UTI) and acute interstitial nephritis. The presence of WBC casts differentiates upper urinary tract infection from lower UTI (cystitis). WBC casts are also seen in transplant rejection.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Microscopic Sediment Analysis", difficulty: 2, cognitiveLevel: "application", learningObjective: "Know WBC cast significance" },
  { stem: "A urine specimen with a strong ammonia odor and alkaline pH most likely has:", options: ["Diabetic ketoacidosis", "Bacterial contamination with urea-splitting organisms", "Maple syrup urine disease", "Phenylketonuria"], correctAnswer: 1, rationaleLong: "Urea-splitting bacteria (Proteus, some Klebsiella) produce urease, which converts urea to ammonia, raising urine pH to alkaline levels (>8.0). This causes a strong ammonia odor and is associated with UTIs and improperly preserved specimens. Triple phosphate (struvite) crystals may form in this alkaline environment.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Physical Examination of Urine", difficulty: 2, cognitiveLevel: "application", learningObjective: "Correlate urine findings with clinical conditions" },
  { stem: "Bilirubin on the urine dipstick indicates:", options: ["Hemolytic anemia", "Liver disease or biliary obstruction (conjugated bilirubinemia)", "Normal finding in concentrated urine", "Urinary tract infection"], correctAnswer: 1, rationaleLong: "Only conjugated (direct) bilirubin appears in urine because it is water-soluble. Unconjugated bilirubin is bound to albumin and cannot pass through the glomerulus. Positive urine bilirubin indicates hepatocellular disease or biliary obstruction (where conjugated bilirubin 'backs up' into the blood and is filtered by the kidneys).", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Chemical Examination (Dipstick)", difficulty: 2, cognitiveLevel: "application", learningObjective: "Interpret urine bilirubin" },
  { stem: "The Tamm-Horsfall protein (uromodulin) is:", options: ["A plasma protein filtered by the glomerulus", "A mucoprotein secreted by renal tubular cells that forms the matrix of urinary casts", "An abnormal protein found only in disease", "A bacterial product"], correctAnswer: 1, rationaleLong: "Tamm-Horsfall protein (uromodulin) is a glycoprotein secreted by the cells of the thick ascending loop of Henle and distal tubule. It forms the matrix of all urinary casts. Hyaline casts (composed solely of Tamm-Horsfall protein) can be seen in small numbers in normal urine, especially after exercise or dehydration.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Microscopic Sediment Analysis", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know Tamm-Horsfall protein function" },
  { stem: "A CSF specimen appears xanthochromic (yellow). This indicates:", options: ["Traumatic tap", "Previous subarachnoid hemorrhage", "Normal finding", "Bacterial contamination"], correctAnswer: 1, rationaleLong: "Xanthochromia (yellow/orange discoloration of CSF) indicates previous subarachnoid hemorrhage (SAH). It is caused by the breakdown of hemoglobin to oxyhemoglobin, methemoglobin, and bilirubin over several hours. Xanthochromia differentiates true SAH from a traumatic tap, where blood is freshly introduced and supernatant should be clear.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Cerebrospinal Fluid (CSF)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Interpret CSF xanthochromia" },
  { stem: "A urine dipstick tests for protein using the principle of:", options: ["Precipitation with sulfosalicylic acid", "Protein error of indicators (pH indicator bromophenol blue)", "Biuret reaction", "Immunoassay"], correctAnswer: 1, rationaleLong: "The urine dipstick protein pad uses the 'protein error of indicators' principle. The indicator (tetrabromophenol blue) changes color in the presence of protein (primarily albumin). The pad is most sensitive to albumin and may miss Bence Jones proteins, hemoglobin, and other non-albumin proteins. SSA precipitation detects all proteins.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Chemical Examination (Dipstick)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know the dipstick protein detection principle" },
  { stem: "Oval fat bodies in urine are characteristic of:", options: ["Urinary tract infection", "Nephrotic syndrome", "Acute cystitis", "Diabetes insipidus"], correctAnswer: 1, rationaleLong: "Oval fat bodies (OFBs) are renal tubular epithelial cells (or macrophages) that have absorbed lipid. They are characteristic of nephrotic syndrome, where massive proteinuria leads to lipiduria. Under polarized microscopy, cholesterol within OFBs shows a 'Maltese cross' pattern. OFBs may also appear as fatty casts and free fat droplets.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Microscopic Sediment Analysis", difficulty: 3, cognitiveLevel: "recall", learningObjective: "Know oval fat body significance" },
  { stem: "Which urinalysis finding is NOT typically detected by the dipstick?", options: ["Glucose", "Protein (albumin)", "Ascorbic acid", "Red blood cells"], correctAnswer: 2, rationaleLong: "While ascorbic acid (vitamin C) interferes with several dipstick reactions (glucose, blood, bilirubin, nitrite — causing false negatives), most standard dipsticks detect its presence as a separate pad. However, not all dipstick brands include an ascorbic acid pad. The key clinical point is that ascorbic acid causes false-negative results for oxidation-based reactions.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Chemical Examination (Dipstick)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know dipstick interferences" },
  { stem: "Which of the following is NOT a normal component of CSF?", options: ["Glucose", "Protein (15-45 mg/dL)", "RBCs", "Chloride"], correctAnswer: 2, rationaleLong: "Normal CSF should NOT contain RBCs. The presence of RBCs in CSF indicates either a traumatic tap (blood introduced during collection) or hemorrhage (subarachnoid or intracerebral). A traumatic tap typically shows decreasing RBC counts in sequential tubes, while true hemorrhage shows consistent RBC counts.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Cerebrospinal Fluid (CSF)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know normal CSF components" },
  { stem: "Clue cells in a vaginal wet mount preparation indicate:", options: ["Trichomonas vaginalis infection", "Bacterial vaginosis (Gardnerella vaginalis)", "Candida infection", "Normal flora"], correctAnswer: 1, rationaleLong: "Clue cells are squamous epithelial cells covered with adherent bacteria (Gardnerella vaginalis and other anaerobes), giving them a stippled or granular appearance with obscured cell borders. They are one of the Amsel criteria for diagnosing bacterial vaginosis. Other criteria include thin grayish discharge, pH >4.5, and positive whiff test.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Microscopic Sediment Analysis", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Identify clue cells" },
  { stem: "Fecal fat staining with Sudan III is used to screen for:", options: ["Celiac disease", "Malabsorption/steatorrhea", "Colon cancer", "Inflammatory bowel disease"], correctAnswer: 1, rationaleLong: "Sudan III (or Sudan IV/Oil Red O) staining of fecal specimens detects excessive fat (steatorrhea), which indicates fat malabsorption. Neutral fat droplets stain orange-red. The quantitative 72-hour fecal fat collection (>7 g/day is abnormal) is the gold standard. Causes include pancreatic insufficiency, celiac disease, and bile salt deficiency.", blueprintCategory: "Urinalysis & Body Fluids", subtopic: "Fecal Occult Blood & Fecal Analysis", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know fecal fat testing" },
];

const immunologyQuestions: MltQuestion[] = [
  { stem: "The principle of ELISA (enzyme-linked immunosorbent assay) involves:", options: ["Agglutination of antigen-coated particles", "Enzyme-labeled antibody binding to antigen, producing a color change", "Fluorescent antibody detection", "Precipitation in gel"], correctAnswer: 1, rationaleLong: "ELISA uses enzyme-labeled antibodies (conjugate) that bind to antigen. After washing to remove unbound conjugate, a chromogenic substrate is added. The enzyme converts the substrate to a colored product, which is measured spectrophotometrically. Common formats include direct, indirect, sandwich, and competitive ELISA.", blueprintCategory: "Immunology / Serology", subtopic: "ELISA & EIA", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know ELISA principle" },
  { stem: "A positive ANA (antinuclear antibody) test with a homogeneous pattern is most associated with:", options: ["Scleroderma", "Systemic lupus erythematosus (SLE)", "Sjögren syndrome", "Mixed connective tissue disease"], correctAnswer: 1, rationaleLong: "A homogeneous (diffuse) ANA pattern is associated with antibodies to dsDNA and histones, which are most commonly seen in SLE and drug-induced lupus. The speckled pattern is seen in many autoimmune conditions. The centromere pattern is associated with limited scleroderma (CREST). The nucleolar pattern is associated with diffuse scleroderma.", blueprintCategory: "Immunology / Serology", subtopic: "Autoimmune Markers (ANA, RF, Anti-dsDNA)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Correlate ANA patterns with diseases" },
  { stem: "The RPR (Rapid Plasma Reagin) test screens for:", options: ["HIV", "Syphilis", "Hepatitis B", "Rheumatoid arthritis"], correctAnswer: 1, rationaleLong: "RPR is a non-treponemal screening test for syphilis that detects reagin antibodies (anti-cardiolipin) produced in response to Treponema pallidum infection. Positive RPR results must be confirmed with a treponemal test (FTA-ABS or TP-PA). RPR can have biological false positives in SLE, pregnancy, and other conditions.", blueprintCategory: "Immunology / Serology", subtopic: "Syphilis Testing (RPR, FTA-ABS)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know syphilis screening tests" },
  { stem: "The confirmatory test for syphilis after a positive RPR is:", options: ["Western blot", "FTA-ABS (fluorescent treponemal antibody absorption)", "ELISA", "Complement fixation"], correctAnswer: 1, rationaleLong: "FTA-ABS (fluorescent treponemal antibody absorption) is a specific treponemal test used to confirm a positive non-treponemal screening test (RPR or VDRL). It detects antibodies against T. pallidum using indirect immunofluorescence. Once positive, FTA-ABS usually remains positive for life, even after treatment.", blueprintCategory: "Immunology / Serology", subtopic: "Syphilis Testing (RPR, FTA-ABS)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know syphilis confirmatory tests" },
  { stem: "The current recommended HIV testing algorithm begins with:", options: ["Western blot", "HIV RNA PCR", "4th generation combination antigen/antibody immunoassay (p24 Ag + HIV-1/2 Ab)", "Rapid HIV antibody test"], correctAnswer: 2, rationaleLong: "The CDC-recommended HIV testing algorithm uses a 4th generation immunoassay that detects both HIV-1/2 antibodies and p24 antigen as the initial screening test. This detects acute HIV infection earlier than antibody-only tests. Reactive screens are followed by an HIV-1/HIV-2 differentiation immunoassay, then HIV-1 RNA NAT if needed.", blueprintCategory: "Immunology / Serology", subtopic: "HIV Testing Algorithms", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know the HIV testing algorithm" },
  { stem: "HBsAg positive, anti-HBc IgM positive, and anti-HBs negative indicates:", options: ["Chronic hepatitis B", "Acute hepatitis B infection", "Hepatitis B immunity from vaccination", "Recovery from hepatitis B"], correctAnswer: 1, rationaleLong: "HBsAg positive indicates active HBV infection. Anti-HBc IgM positive indicates recent/acute infection (IgM is the first antibody class produced). Anti-HBs negative means no protective immunity yet. This serological pattern is characteristic of acute hepatitis B. Chronic HBV shows HBsAg positive with anti-HBc IgG positive (not IgM).", blueprintCategory: "Immunology / Serology", subtopic: "Hepatitis Serology (HBsAg, Anti-HBc, Anti-HCV)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Interpret hepatitis B serology" },
  { stem: "A patient has anti-HBs positive only (all other HBV markers negative). This indicates:", options: ["Acute hepatitis B", "Chronic hepatitis B", "Immunity from vaccination", "Hepatitis B window period"], correctAnswer: 2, rationaleLong: "Anti-HBs positive as the only HBV marker indicates immunity from vaccination. The hepatitis B vaccine contains recombinant HBsAg, which stimulates anti-HBs production. Natural immunity (from resolved infection) would show both anti-HBs and anti-HBc positive.", blueprintCategory: "Immunology / Serology", subtopic: "Hepatitis Serology (HBsAg, Anti-HBc, Anti-HCV)", difficulty: 2, cognitiveLevel: "application", learningObjective: "Interpret hepatitis B vaccination immunity" },
  { stem: "Rheumatoid factor (RF) is an autoantibody directed against:", options: ["Nuclear antigens", "The Fc portion of IgG", "Platelet antigens", "Thyroid antigens"], correctAnswer: 1, rationaleLong: "Rheumatoid factor (RF) is an autoantibody (usually IgM class) directed against the Fc portion of IgG. It is found in approximately 70-80% of patients with rheumatoid arthritis but is not specific — it can also be positive in other autoimmune diseases, chronic infections, and even in healthy elderly individuals.", blueprintCategory: "Immunology / Serology", subtopic: "Autoimmune Markers (ANA, RF, Anti-dsDNA)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know rheumatoid factor" },
  { stem: "The complement system's classical pathway is activated by:", options: ["Mannose on bacterial surfaces", "Alternative pathway amplification", "Antigen-antibody (immune) complexes", "Spontaneous C3 hydrolysis"], correctAnswer: 2, rationaleLong: "The classical complement pathway is activated by antigen-antibody complexes (IgG or IgM bound to antigen). C1q binds to the Fc portion of the antibody, initiating the cascade (C1 → C4 → C2 → C3 → C5-C9 membrane attack complex). The lectin pathway is activated by mannose. The alternative pathway is activated by microbial surfaces.", blueprintCategory: "Immunology / Serology", subtopic: "Complement System", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know complement pathway activation" },
  { stem: "Flow cytometry is primarily used in the clinical laboratory for:", options: ["Bacterial identification", "Immunophenotyping of leukemias and lymphomas", "Coagulation testing", "Protein electrophoresis"], correctAnswer: 1, rationaleLong: "Flow cytometry is used to identify and quantify cell surface and intracellular markers (CD markers) using fluorescent-labeled antibodies. Its primary applications include immunophenotyping leukemias/lymphomas, CD4 T-cell counting in HIV patients, PNH diagnosis, stem cell enumeration, and DNA ploidy analysis.", blueprintCategory: "Immunology / Serology", subtopic: "Flow Cytometry", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know flow cytometry applications" },
  { stem: "Anti-dsDNA antibodies are highly specific for:", options: ["Rheumatoid arthritis", "Systemic lupus erythematosus", "Sjögren syndrome", "Polymyositis"], correctAnswer: 1, rationaleLong: "Anti-double-stranded DNA (anti-dsDNA) antibodies are highly specific (>95%) for systemic lupus erythematosus (SLE). They correlate with disease activity, especially lupus nephritis. Anti-dsDNA levels fluctuate with disease flares and can be used to monitor treatment response. They are measured by ELISA, Crithidia luciliae immunofluorescence, or Farr assay.", blueprintCategory: "Immunology / Serology", subtopic: "Autoimmune Markers (ANA, RF, Anti-dsDNA)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know anti-dsDNA specificity" },
  { stem: "A monospot test detects heterophile antibodies in:", options: ["Hepatitis A", "HIV infection", "Infectious mononucleosis (EBV)", "Cytomegalovirus infection"], correctAnswer: 2, rationaleLong: "The monospot (heterophile antibody test) detects heterophile antibodies produced during EBV infection (infectious mononucleosis). These antibodies agglutinate horse, sheep, or bovine RBCs. The test may be negative early in infection (first 1-2 weeks). False negatives are more common in children <4 years. EBV-specific antibodies (VCA-IgM) are more sensitive.", blueprintCategory: "Immunology / Serology", subtopic: "Antigen-Antibody Reactions", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know the monospot test" },
  { stem: "C3 and C4 complement levels are both decreased. This is most consistent with:", options: ["Alternative pathway activation", "Classical pathway activation", "Lectin pathway activation only", "Complement deficiency"], correctAnswer: 1, rationaleLong: "Decreased C3 AND C4 indicates classical pathway activation (which consumes C4, C2, and C3 sequentially). This is seen in SLE, serum sickness, and immune complex diseases. Alternative pathway activation consumes C3 but NOT C4 (C4 is normal). Both pathways converge at C3, so C3 is decreased in both.", blueprintCategory: "Immunology / Serology", subtopic: "Complement System", difficulty: 3, cognitiveLevel: "application", learningObjective: "Interpret complement levels" },
];

const labOperationsQuestions: MltQuestion[] = [
  { stem: "A QC result violates the 1-3s Westgard rule. The appropriate action is:", options: ["Report patient results — this is a warning rule", "Reject the analytical run and investigate", "Repeat the QC only", "Recalibrate and continue testing"], correctAnswer: 1, rationaleLong: "The 1-3s rule is a rejection rule — any single QC result that exceeds ±3 SD from the mean indicates a random error or a significant systematic error. Patient results from this run should NOT be reported until the problem is identified and corrected. Troubleshooting includes checking reagents, calibration, sample handling, and instrument function.", blueprintCategory: "Laboratory Operations & Quality Management", subtopic: "Quality Control (Levey-Jennings, Westgard Rules)", difficulty: 2, cognitiveLevel: "application", learningObjective: "Apply Westgard rejection rules" },
  { stem: "Levey-Jennings charts plot:", options: ["Patient results over time", "QC values over time relative to the mean and SD", "Calibration curves", "Cost analysis data"], correctAnswer: 1, rationaleLong: "Levey-Jennings (LJ) charts plot quality control values over time, with the mean and ±1, 2, 3 SD lines indicated. They allow visualization of trends (gradual shift), shifts (sudden change in level), and random error patterns. Westgard rules are applied to LJ chart data to determine when corrective action is needed.", blueprintCategory: "Laboratory Operations & Quality Management", subtopic: "Quality Control (Levey-Jennings, Westgard Rules)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know Levey-Jennings chart purpose" },
  { stem: "CLIA '88 categorizes laboratory tests into which complexity levels?", options: ["Simple and complex", "Waived, moderate complexity, and high complexity", "Level 1, Level 2, and Level 3", "Basic, intermediate, and advanced"], correctAnswer: 1, rationaleLong: "CLIA '88 (Clinical Laboratory Improvement Amendments) categorizes laboratory tests into three complexity categories: waived (simple, low-risk tests like dipstick urinalysis, glucose meters), moderate complexity, and high complexity. The complexity level determines personnel requirements, QC requirements, proficiency testing, and inspection requirements.", blueprintCategory: "Laboratory Operations & Quality Management", subtopic: "CLIA / CAP / Accreditation Canada Standards", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know CLIA test complexity categories" },
  { stem: "Proficiency testing (PT) is required for:", options: ["Only waived tests", "All tests performed in the laboratory", "Only high-complexity tests", "Only blood bank tests"], correctAnswer: 1, rationaleLong: "CLIA requires that laboratories participate in proficiency testing (external quality assessment) for all regulated analytes/tests they perform. PT samples are tested as routine patient samples, and results are submitted to the PT provider. Failure to achieve satisfactory scores can result in corrective action or loss of certification.", blueprintCategory: "Laboratory Operations & Quality Management", subtopic: "Proficiency Testing", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know proficiency testing requirements" },
  { stem: "A specimen is received with a patient ID that does not match the requisition. The correct action is:", options: ["Test the specimen and add a note", "Reject the specimen and request recollection", "Call the floor to verify verbally", "Test under the requisition name"], correctAnswer: 1, rationaleLong: "Patient identification errors are a critical safety issue. If the specimen label and requisition do not match, the specimen must be rejected and a new specimen collected with proper identification. Verbal verification is not acceptable for correcting ID discrepancies. Proper patient identification (two unique identifiers) must be verified at the time of collection.", blueprintCategory: "Laboratory Operations & Quality Management", subtopic: "Specimen Rejection Criteria", difficulty: 1, cognitiveLevel: "application", learningObjective: "Apply specimen rejection criteria" },
  { stem: "Which class of fire extinguisher is appropriate for a chemical fire in the laboratory?", options: ["Class A (water)", "Class B (CO2 or dry chemical)", "Class D (metal fires)", "Class K (cooking fires)"], correctAnswer: 1, rationaleLong: "Class B fire extinguishers (CO2, dry chemical, or foam) are appropriate for flammable liquid and chemical fires. Class A extinguishers (water) are for ordinary combustibles. ABC-rated dry chemical extinguishers are most commonly found in laboratories as they cover multiple fire classes. Never use water on a chemical or electrical fire.", blueprintCategory: "Laboratory Operations & Quality Management", subtopic: "Laboratory Safety (Chemical, Biological, Radiation)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know fire safety in the laboratory" },
  { stem: "The Safety Data Sheet (SDS) provides information about:", options: ["Patient results", "Chemical hazards, handling, storage, and emergency procedures", "Equipment maintenance schedules", "Quality control procedures"], correctAnswer: 1, rationaleLong: "The Safety Data Sheet (formerly MSDS) is a standardized 16-section document that provides comprehensive information about chemical products including: identification, hazard identification, composition, first aid, firefighting, accidental release, handling/storage, exposure controls, physical/chemical properties, stability, toxicology, ecology, disposal, transport, and regulatory information.", blueprintCategory: "Laboratory Operations & Quality Management", subtopic: "Laboratory Safety (Chemical, Biological, Radiation)", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Know SDS purpose" },
  { stem: "The 2-2s Westgard rule is violated when:", options: ["Two consecutive QC results exceed ±2 SD on the same side of the mean", "Any single result exceeds 2 SD", "Two results in different runs exceed 2 SD", "QC mean shifts by 2 SD"], correctAnswer: 0, rationaleLong: "The 2-2s rule is violated when two consecutive QC results both exceed ±2 SD on the same side of the mean. This indicates systematic error (shift or trend). It can also apply across two levels of QC if both exceed 2 SD on the same side. The 2-2s rule helps detect systematic error that the 1-2s warning flag might miss.", blueprintCategory: "Laboratory Operations & Quality Management", subtopic: "Quality Control (Levey-Jennings, Westgard Rules)", difficulty: 3, cognitiveLevel: "application", learningObjective: "Understand Westgard multi-rules" },
  { stem: "A trend on a Levey-Jennings chart indicates:", options: ["Random error", "Gradual, progressive change in one direction over 6+ consecutive points", "Sudden shift in the mean", "Acceptable instrument performance"], correctAnswer: 1, rationaleLong: "A trend on a Levey-Jennings chart is a gradual, progressive increase or decrease in QC values over time (typically 6-7 consecutive points moving in the same direction). Trends often indicate deteriorating reagents, aging lamp, or gradual calibration drift. A shift is a sudden change in the mean level.", blueprintCategory: "Laboratory Operations & Quality Management", subtopic: "Quality Control (Levey-Jennings, Westgard Rules)", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Distinguish trends from shifts in QC" },
  { stem: "Which of the following is a pre-analytical error?", options: ["Incorrect wavelength selection", "Wrong test ordered by the physician", "Mislabeled specimen", "Incorrect dilution of reagent"], correctAnswer: 2, rationaleLong: "Pre-analytical errors occur before the specimen is analyzed and account for approximately 60-70% of all laboratory errors. Examples include mislabeled specimens, incorrect specimen type, hemolysis from difficult collection, improper transport conditions, and fasting violations. Wrong test orders are technically pre-pre-analytical (clinical decision).", blueprintCategory: "Laboratory Operations & Quality Management", subtopic: "Quality Assurance Programs", difficulty: 1, cognitiveLevel: "recall", learningObjective: "Classify types of laboratory errors" },
  { stem: "The order of draw for venipuncture blood collection tubes is:", options: ["EDTA, SST, citrate, heparin", "Blood cultures, citrate (blue), SST/serum (red/gold), heparin (green), EDTA (lavender), fluoride (gray)", "Any order is acceptable", "Red, blue, green, lavender, gray"], correctAnswer: 1, rationaleLong: "The standard order of draw (CLSI H3-A6) is: 1) Blood cultures (sterile), 2) Citrate (blue top), 3) Serum tubes (red/gold/SST), 4) Heparin (green), 5) EDTA (lavender), 6) Fluoride/oxalate (gray). This order prevents cross-contamination of additives between tubes, which could affect test results.", blueprintCategory: "Laboratory Operations & Quality Management", subtopic: "Specimen Rejection Criteria", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know the order of draw" },
  { stem: "A critical value for potassium is 6.5 mEq/L. The technologist should:", options: ["Report it in the LIS and move on", "Verify the result and immediately notify the patient's healthcare provider", "Wait for the physician to check the result", "Repeat the test the next day"], correctAnswer: 1, rationaleLong: "Critical (panic) values are laboratory results that indicate a potentially life-threatening condition requiring immediate clinical action. The technologist must verify the result (check for hemolysis, repeat if necessary), immediately notify the responsible healthcare provider (within a defined time frame, typically 30 minutes), and document the notification (who, when, and read-back verification).", blueprintCategory: "Laboratory Operations & Quality Management", subtopic: "Quality Assurance Programs", difficulty: 2, cognitiveLevel: "application", learningObjective: "Apply critical value reporting procedures" },
  { stem: "Delta checks are used to:", options: ["Compare patient results with reference ranges", "Detect possible specimen mix-up by comparing current results with previous results", "Verify QC performance", "Calculate reference ranges"], correctAnswer: 1, rationaleLong: "Delta checks compare a patient's current result with their previous result. A significant unexplained change (exceeding a predetermined limit) may indicate specimen mislabeling, misidentification, or a sudden clinical change. Delta check flags should be investigated before reporting results. Common analytes monitored include hemoglobin, MCV, and electrolytes.", blueprintCategory: "Laboratory Operations & Quality Management", subtopic: "Quality Assurance Programs", difficulty: 2, cognitiveLevel: "recall", learningObjective: "Know delta check purpose" },
];

const allQuestions: MltQuestion[] = [
  ...chemistryQuestions,
  ...hematologyQuestions,
  ...hemostasisQuestions,
  ...microbiologyQuestions,
  ...bloodBankQuestions,
  ...urinalysisQuestions,
  ...immunologyQuestions,
  ...labOperationsQuestions,
];

async function seed() {
  const databaseUrl = process.env.PROD_DATABASE_URL || process.env.DATABASE_URL;
  if (!databaseUrl) {
    console.error("DATABASE_URL not set");
    process.exit(1);
  }

  const pool = new Pool({ connectionString: databaseUrl });

  console.log(`Total questions to insert: ${allQuestions.length}`);

  const distribution: Record<string, number> = {};
  const diffDist: Record<number, number> = {};
  const cogDist: Record<string, number> = {};

  for (const q of allQuestions) {
    distribution[q.blueprintCategory] = (distribution[q.blueprintCategory] || 0) + 1;
    diffDist[q.difficulty] = (diffDist[q.difficulty] || 0) + 1;
    cogDist[q.cognitiveLevel] = (cogDist[q.cognitiveLevel] || 0) + 1;
  }

  console.log("Distribution by discipline:", distribution);
  console.log("Distribution by difficulty:", diffDist);
  console.log("Distribution by cognitive level:", cogDist);

  let inserted = 0;
  let errors = 0;

  for (let i = 0; i < allQuestions.length; i++) {
    const q = allQuestions[i];
    try {
      await pool.query(
        `INSERT INTO allied_questions (
          id, career_type, stem, options, correct_answer, rationale_long,
          learning_objective, blueprint_category, subtopic, difficulty,
          cognitive_level, question_type, status, created_at
        ) VALUES (
          gen_random_uuid(), 'mlt', $1, $2, $3, $4,
          $5, $6, $7, $8,
          $9, 'mcq', 'active', NOW()
        )`,
        [
          q.stem,
          JSON.stringify(q.options),
          q.correctAnswer,
          q.rationaleLong,
          q.learningObjective,
          q.blueprintCategory,
          q.subtopic,
          q.difficulty,
          q.cognitiveLevel,
        ]
      );
      inserted++;
    } catch (e: any) {
      console.error(`Error inserting question ${i + 1}: ${e.message}`);
      errors++;
    }
  }

  console.log(`\nInserted: ${inserted}, Errors: ${errors}`);
  await pool.end();
}

seed().catch(console.error);
